  8→namespace TmRobotEx.Bridge;
  9→
 10→/// <summary>
 11→/// TCP 5001 브릿지 서버.
 12→/// sd_bridge.py의 C# 포팅.
 13→/// TMscript(TCP) → 이 서버 → Compute Box(XML-RPC)
 14→/// </summary>
 15→public class BridgeServer
 16→{
 17→    private TcpListener? _listener;
 18→    private CancellationTokenSource? _cts;
 19→    private readonly int _port;
 20→    private readonly SemaphoreSlim _cmdLock = new(1, 1);
 21→
 22→    private const double BUSY_POLL_SEC = 0.1;
 23→    private const double BUSY_TIMEOUT_SEC = 30;
 24→
 25→    public ComputeBoxClient CbClient { get; }
 26→    public WorkPlateData? PlateData { get; set; }
 27→
 28→    // 시나리오 연동
 29→    private ScrewScenario? _scenario;
 30→    private int _currentStepIndex;
 31→    private volatile bool _scenarioRunning;
 32→
 33→    // 마지막 체결 결과 (tqDecision 용)
 34→    private volatile bool _lastTightenOk;
 35→
 36→    // next_step 블로킹 대기용
 37→    private TaskCompletionSource<bool>? _scenarioReadyTcs;
 38→    private readonly object _tcsLock = new();
 39→
 40→    public event Action<string>? LogMessage;
 41→
 42→    /// <summary>
 43→    /// 스텝 시작 (stepIndex, operation) — TMflow가 next_step 요청 시
 44→    /// </summary>
 45→    public event Action<int, ScrewOperation>? StepStarted;
 46→
 47→    /// <summary>
 48→    /// 스텝 완료 (stepIndex, operation, success, achievedTorque) — TMflow가 step_result 보고 시
 49→    /// </summary>
 50→    public event Action<int, ScrewOperation, bool, double>? StepCompleted;
 51→
 52→    /// <summary>
 53→    /// 시나리오 전체 완료
 54→    /// </summary>
 55→    public event Action? ScenarioCompleted;
 56→
 57→    public BridgeServer(int port, string cbUrl, int cbTimeout)
 58→    {
 59→        _port = port;
 60→        CbClient = new ComputeBoxClient(cbUrl, cbTimeout);
 61→        // CB 로그를 브릿지 로그로 전달
 62→        CbClient.LogMessage += msg => LogMessage?.Invoke(msg);
 63→    }
 64→
 65→    private void Log(string tag, string msg) => LogMessage?.Invoke($"[{tag}] {msg}");
 66→
 67→    /// <summary>
 68→    /// 시나리오 실행 모드 시작 (TMflow 대기)
 69→    /// </summary>
 70→    public void StartScenario(ScrewScenario scenario)
 71→    {
 72→        _scenario = scenario;
 73→        _currentStepIndex = 0;
 74→        _scenarioRunning = true;
 75→        Log("시나리오", $"시작: {scenario.Name} ({scenario.Operations.Count}개 스텝)");
 76→
 77→        // 블로킹 대기 중인 next_step 요청 깨우기
 78→        lock (_tcsLock)
 79→        {
 80→            _scenarioReadyTcs?.TrySetResult(true);
 81→            _scenarioReadyTcs = null;
 82→        }
 83→    }
 84→
 85→    /// <summary>
 86→    /// 시나리오 실행 모드 정지
 87→    /// </summary>
 88→    public void StopScenario()
 89→    {
 90→        _scenarioRunning = false;
 91→        _scenario = null;
 92→        Log("시나리오", "중지");
 93→
 94→        // 블로킹 대기 중인 next_step 요청 취소
 95→        lock (_tcsLock)
 96→        {
 97→            _scenarioReadyTcs?.TrySetResult(false);
 98→            _scenarioReadyTcs = null;
 99→        }
100→    }
101→
102→    public bool IsScenarioRunning => _scenarioRunning;
103→
104→    /// <summary>
105→    /// UI에서 직접 명령 실행 (브릿지 디스패처 경유)
106→    /// </summary>
107→    public Task<string> ExecuteAsync(string cmdLine) => DispatchAsync(cmdLine);
108→
109→    public Task StartAsync()
110→    {
111→        _cts = new CancellationTokenSource();
112→        _listener = new TcpListener(IPAddress.Any, _port);
113→        _listener.Server.SetSocketOption(
114→            System.Net.Sockets.SocketOptionLevel.Socket,
115→            System.Net.Sockets.SocketOptionName.ReuseAddress, true);
116→        _listener.Start();
117→        Log("서버", $"대기 중 — 0.0.0.0:{_port}");
118→
119→        // 수신 루프 (백그라운드)
120→        _ = Task.Run(() => AcceptLoop(_cts.Token));
121→
122→        // Compute Box 연결 확인 (백그라운드, 서버 시작 후)
123→        _ = Task.Run(CheckComputeBoxAsync);
124→
125→        return Task.CompletedTask;
126→    }
127→
128→    private async Task CheckComputeBoxAsync()
129→    {
130→        Log("초기화", $"Compute Box ({CbClient.Url}) 연결 중...");
131→        try
132→        {
133→            var busy = await CbClient.GetBusyAsync();
134→            var torque = await CbClient.GetTorqueAsync();
135→            var error = await CbClient.GetErrorCodeAsync();
136→            Log("초기화", "Compute Box 연결 OK");
137→            Log("초기화", $"  busy={Convert.ToInt32(busy)}  torque={torque:F2}  error={error}");
138→        }
139→        catch (Exception ex)
140→        {
141→            Log("오류", $"Compute Box 연결 실패: {ex.Message}");
142→            Log("오류", "Compute Box 전원/네트워크 확인 후 재시도");
143→        }
144→    }
145→
146→    public void Stop()
147→    {
148→        Log("서버", "종료 중...");
149→        _cts?.Cancel();
150→        _cts?.Dispose();
151→        _cts = null;
152→        try { _listener?.Stop(); } catch { }
153→        _listener = null;
154→        CbClient.Dispose();
155→
156→        lock (_tcsLock)
157→        {
158→            _scenarioReadyTcs?.TrySetResult(false);
159→            _scenarioReadyTcs = null;
160→        }
161→        Log("서버", "종료 완료");
162→    }
163→
164→    private async Task AcceptLoop(CancellationToken token)
165→    {
166→        while (!token.IsCancellationRequested)
167→        {
168→            try
169→            {
170→                var client = await _listener!.AcceptTcpClientAsync(token);
171→                var addr = ((IPEndPoint)client.Client.RemoteEndPoint!).Address;
172→                Log("연결", $"{addr} 접속");
173→                _ = Task.Run(() => HandleClient(client, addr.ToString(), token));
174→            }
175→            catch (OperationCanceledException) { break; }
176→            catch (Exception ex)
177→            {
178→                if (!token.IsCancellationRequested)
179→                    Log("오류", $"Accept 오류: {ex.Message}");
180→            }
181→        }
182→    }
183→
184→    private async Task HandleClient(TcpClient client, string addr, CancellationToken token)
185→    {
186→        using (client)
187→        {
188→            try
189→            {
190→                client.ReceiveTimeout = 60000;
191→                using var stream = client.GetStream();
192→                // BOM 없는 UTF-8 (파이썬 브릿지와 동일)
193→                var utf8 = new UTF8Encoding(false);
194→                using var reader = new StreamReader(stream, utf8, detectEncodingFromByteOrderMarks: false);
195→
196→                while (!token.IsCancellationRequested)
197→                {
198→                    string? line;
199→                    try
200→                    {
201→                        line = await reader.ReadLineAsync(token);
202→                    }
203→                    catch { break; }
204→
205→                    if (line == null) break;
206→
207→                    line = line.Trim();
208→                    if (string.IsNullOrEmpty(line)) continue;
209→
210→                    Log("수신", $"{addr} > {line}");
211→                    var t0 = DateTime.Now;
212→
213→                    string result;
214→                    try
215→                    {
216→                        result = await DispatchAsync(line);
217→                    }
218→                    catch (Exception ex)
219→                    {
220→                        result = $"ERR:{ex.Message}";
221→                        Log("오류", $"처리 중 예외: {ex.Message}");
222→                    }
223→
224→                    var ms = (DateTime.Now - t0).TotalMilliseconds;
225→                    Log("응답", $"{addr} < {result}  ({ms:F0}ms)");
226→
227→                    // 파이썬과 동일: result + \r\n, 바이트로 직접 전송
228→                    try
229→                    {
230→                        var responseBytes = utf8.GetBytes(result + "\r\n");
231→                        await stream.WriteAsync(responseBytes, token);
232→                        await stream.FlushAsync(token);
233→                    }
234→                    catch { break; }
235→                }
236→            }
237→            catch (OperationCanceledException) { }
238→            catch (Exception ex)
239→            {
240→                if (!token.IsCancellationRequested)
241→                    Log("오류", $"{addr} 핸들러 예외: {ex.Message}");
242→            }
243→            finally
244→            {
245→                Log("종료", $"{addr} 연결 끊김");
246→            }
247→        }
248→    }
249→
250→    /// <summary>
251→    /// 명령 디스패처 (SemaphoreSlim으로 직렬화)
252→    /// </summary>
253→    private async Task<string> DispatchAsync(string cmdLine)
254→    {
255→        var parts = cmdLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
256→        if (parts.Length == 0) return "ERR:빈 명령";
257→
258→        var cmd = parts[0].ToLower();
259→        var args = parts[1..];
260→
261→        // next_step은 블로킹 대기하므로 cmdLock 밖에서 처리
262→        if (cmd == "next_step")
263→        {
264→            try { return await CmdNextStepAsync(); }
265→            catch (Exception ex)
266→            {
267→                Log("오류", $"dispatch 예외: {ex.Message}");
268→                return $"ERR:{ex.Message}";
269→            }
270→        }
271→
272→        await _cmdLock.WaitAsync();
273→        try
274→        {
275→            return cmd switch
276→            {
277→                "config" => await CmdConfig(args),
278→                "pickup" => await CmdPickup(args),
279→                "tighten" => await CmdTighten(args),
280→                "loosen" => await CmdLoosen(args),
281→                "shank" => await CmdShank(args),
282→                "stop" => await CmdStop(),
283→                "status" => await CmdStatus(),
284→                "recover" => await CmdRecover(),
285→                "raw" => await CmdRaw(args),
286→                "next_hole" => CmdNextHole(),
287→                "hole_result" => CmdHoleResult(args),
288→                "get_coord" => CmdGetCoord(args),
289→                "tqdecision" => CmdTqDecision(),
290→                _ => $"ERR:unknown '{cmd}'"
291→            };
292→        }
293→        catch (Exception ex)
294→        {
295→            Log("오류", $"dispatch 예외: {ex.Message}");
296→            return $"ERR:{ex.Message}";
297→        }
298→        finally
299→        {
300→            _cmdLock.Release();
301→        }
302→    }
303→
304→    #region 기본 명령 (sd_bridge.py 동일)
305→
306→    private async Task<string> CmdConfig(string[] args)
307→    {
308→        double extender = args.Length > 0 && double.TryParse(args[0], out var e) ? e : 0;
309→        await CbClient.ConfigAsync(extender);
310→        return $"OK:config extender={extender}";
311→    }
312→
313→    private async Task<string> CmdPickup(string[] args)
314→    {
315→        if (args.Length < 2) return "ERR:pickup <force_N> <len_mm>";
316→        int force = int.Parse(args[0]);
317→        double length = double.Parse(args[1]);
318→
319→        await CbClient.PickupScrewAsync(force, length);
320→        var done = await WaitUntilDone(waitStart: true);
321→        var error = await CbClient.GetErrorCodeAsync();
322→        if (!done) return $"ERR:pickup timeout,error={error}";
323→        if (error != 0) return $"ERR:pickup error={error}";
324→        return "OK:pickup";
325→    }
326→
327→    private async Task<string> CmdTighten(string[] args)
328→    {
329→        if (args.Length < 3) return "ERR:tighten <force_N> <len_mm> <torque_Nm>";
330→        int force = int.Parse(args[0]);
331→        double length = double.Parse(args[1]);
332→        double torque = double.Parse(args[2]);
333→
334→        await CbClient.TightenAsync(force, length, torque);
335→        var done = await WaitUntilDone(waitStart: true);
336→        var achieved = await CbClient.GetTorqueAsync();
337→        var error = await CbClient.GetErrorCodeAsync();
338→
339→        bool success;
340→        string response;
341→        if (!done)
342→        {
343→            success = false;
344→            response = $"ERR:tighten timeout,torque={achieved:F2},error={error}";
345→        }
346→        else if (error != 0)
347→        {
348→            success = false;
349→            response = $"ERR:tighten error={error},torque={achieved:F2}";
350→        }
351→        else if (achieved < 0.15)
352→        {
353→            // 토크 부족 → NG (재시도 필요)
354→            success = false;
355→            await WaitRetract();
356→            response = $"OK:tighten torque={achieved:F2}";
357→        }
358→        else
359→        {
360→            success = true;
361→            await WaitRetract();
362→            response = $"OK:tighten torque={achieved:F2}";
363→        }
364→
365→        _lastTightenOk = success;
366→
367→        // 시나리오 실행 중이면 결과 기록 + 성공 시만 스텝 진행
368→        if (_scenarioRunning && _scenario != null && _currentStepIndex < _scenario.Operations.Count)
369→        {
370→            var op = _scenario.Operations[_currentStepIndex];
371→            var status = success ? HoleStatus.Ok : HoleStatus.Ng;
372→            PlateData?.SetResult(op.Col, op.Row, status, achieved);
373→
374→            Log("시나리오", $"스텝 {_currentStepIndex + 1} 결과: {(success ? "OK" : "NG")}, torque={achieved:F2}");
375→            StepCompleted?.Invoke(_currentStepIndex, op, success, achieved);
376→
377→            // NG면 스텝 진행 안 함 (next_step에서 같은 홀 반환 → 재시도)
378→            if (!success)
379→            {
380→                Log("시나리오", $"스텝 {_currentStepIndex + 1} 재시도 필요 (torque={achieved:F2} < 0.15)");
381→                return response;
382→            }
383→
384→            _currentStepIndex++;
385→
386→            if (_currentStepIndex >= _scenario.Operations.Count)
387→            {
388→                _scenarioRunning = false;
389→                Log("시나리오", $"전체 완료 ({_scenario.Operations.Count}개 스텝)");
390→                ScenarioCompleted?.Invoke();
391→            }
392→        }
393→
394→        return response;
395→    }
396→
397→    private async Task<string> CmdLoosen(string[] args)
398→    {
399→        if (args.Length < 2) return "ERR:loosen <force_N> <len_mm>";
400→        int force = int.Parse(args[0]);
401→        double length = double.Parse(args[1]);
402→
403→        await CbClient.LoosenAsync(force, length);
404→        var done = await WaitUntilDone(waitStart: true);
405→        var error = await CbClient.GetErrorCodeAsync();
406→        if (!done) return $"ERR:loosen timeout,error={error}";
407→        if (error != 0) return $"ERR:loosen error={error}";
408→        await WaitRetract();
409→        return "OK:loosen";
410→    }
411→
412→    private async Task<string> CmdShank(string[] args)
413→    {
414→        if (args.Length < 1) return "ERR:shank <pos> (0=후퇴, 55=전진)";
415→        int pos = int.Parse(args[0]);
416→        await CbClient.MoveShankAsync(pos);
417→        return "OK:shank";
418→    }
419→
420→    private async Task<string> CmdStop()
421→    {
422→        await CbClient.StopAsync();
423→        return "OK:stop";
424→    }
425→
426→    private async Task<string> CmdStatus()
427→    {
428→        var error = await CbClient.GetErrorCodeAsync();
429→        var safety = await CbClient.GetZSafetyActivatedAsync();
430→
431→        if (error != 0 || safety)
432→        {
433→            Log("복구", $"에러/안전 감지 (error={error}, safety={safety}), 자동 복구...");
434→            await CbClient.MoveShankAsync(0);
435→            await Task.Delay(3000);
436→            await WaitUntilDone(timeout: 10);
437→
438→            var error2 = await CbClient.GetErrorCodeAsync();
439→            var safety2 = await CbClient.GetZSafetyActivatedAsync();
440→            if (error2 == 0 && !safety2)
441→                Log("복구", "복구 완료");
442→            else
443→                Log("복구", $"복구 실패 (error={error2}, safety={safety2})");
444→        }
445→
446→        var busy = await CbClient.GetBusyAsync();
447→        var torque = await CbClient.GetTorqueAsync();
448→        error = await CbClient.GetErrorCodeAsync();
449→        return $"OK:busy={Convert.ToInt32(busy)},torque={torque:F2},error={error}";
450→    }
451→
452→    private async Task<string> CmdRecover()
453→    {
454→        Log("복구", "수동 복구 시작 (샹크 후퇴)...");
455→        await CbClient.MoveShankAsync(0);
456→        await Task.Delay(3000);
457→        await WaitUntilDone(timeout: 10);
458→        var error = await CbClient.GetErrorCodeAsync();
459→        var safety = await CbClient.GetZSafetyActivatedAsync();
460→        if (error == 0 && !safety)
461→        {
462→            Log("복구", "복구 완료");
463→            return "OK:recover";
464→        }
465→        Log("복구", $"복구 실패 (error={error}, safety={safety})");
466→        return $"ERR:recover error={error},safety={Convert.ToInt32(safety)}";
467→    }
468→
469→    private async Task<string> CmdRaw(string[] args)
470→    {
471→        if (args.Length == 0) return "ERR:raw <method> [args...]";
472→        var method = args[0];
473→        var callArgs = new object[args.Length - 1];
474→        for (int i = 1; i < args.Length; i++)
475→        {
476→            if (int.TryParse(args[i], out var iv)) callArgs[i - 1] = iv;
477→            else if (double.TryParse(args[i], out var dv)) callArgs[i - 1] = dv;
478→            else callArgs[i - 1] = args[i];
479→        }
480→        var result = await CbClient.CallRawAsync(method, callArgs);
481→        return $"OK:{result}";
482→    }
