486→    #region 확장 명령 (시나리오 연동)
487→
488→    private string CmdNextHole()
489→    {
490→        if (PlateData == null) return "ERR:작업판 없음";
491→        var next = PlateData.GetNextEmpty();
492→        if (next == null) return "ERR:빈 홀 없음";
493→        return $"OK:{next.Value.col},{next.Value.row}";
494→    }
495→
496→    private string CmdHoleResult(string[] args)
497→    {
498→        if (PlateData == null) return "ERR:작업판 없음";
499→        if (args.Length < 4) return "ERR:hole_result <col> <row> <ok|ng> <torque>";
500→        int col = int.Parse(args[0]);
501→        int row = int.Parse(args[1]);
502→        var status = args[2].ToLower() == "ok" ? HoleStatus.Ok : HoleStatus.Ng;
503→        double torque = double.Parse(args[3]);
504→        PlateData.SetResult(col, row, status, torque);
505→        return "OK:hole_result";
506→    }
507→
508→    private string CmdGetCoord(string[] args)
509→    {
510→        if (PlateData == null) return "ERR:작업판 없음";
511→        if (args.Length < 2) return "ERR:get_coord <col> <row>";
512→        int col = int.Parse(args[0]);
513→        int row = int.Parse(args[1]);
514→        // 20mm 피치 기준 좌표 (원점은 (0,0) 홀)
515→        double x = col * 20.0;
516→        double y = row * 20.0;
517→        return $"OK:{x:F1},{y:F1}";
518→    }
