520→    /// <summary>
521→    /// 마지막 체결 결과 반환 (OK 또는 NG)
522→    /// </summary>
523→    private string CmdTqDecision()
524→    {
525→        return _lastTightenOk ? "OK" : "NG";
526→    }
527→
528→    #endregion
529→
530→    #region 시나리오 연동 명령
531→
532→    /// <summary>
533→    /// TMflow → next_step: 다음 작업 스텝의 col,row 반환
534→    /// 시나리오 미실행 시 시작될 때까지 블로킹 대기 (최대 60초)
535→    /// 응답: OK:col,row  또는  DONE  또는  ERR:...
536→    /// </summary>
537→    private async Task<string> CmdNextStepAsync()
538→    {
539→        // 시나리오 완료 상태 → 즉시 DONE 반환
540→        if (!_scenarioRunning && _scenario != null && _currentStepIndex >= _scenario.Operations.Count)
541→        {
542→            return "DONE";
543→        }
544→
545→        // 시나리오 미실행 → 시작될 때까지 대기
546→        if (!_scenarioRunning || _scenario == null)
547→        {
548→            Log("시나리오", "next_step 대기 중 (PC에서 실행 버튼 대기)...");
549→
550→            TaskCompletionSource<bool> tcs;
551→            lock (_tcsLock)
552→            {
553→                _scenarioReadyTcs ??= new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
554→                tcs = _scenarioReadyTcs;
555→            }
556→
557→            // 시나리오 시작 또는 서버 종료까지 무한 대기
558→            await tcs.Task;
559→
560→            if (!tcs.Task.Result)
561→            {
562→                return "ERR:시나리오 취소";
563→            }
564→
565→            Log("시나리오", "시나리오 시작 신호 수신");
566→        }
567→
568→        if (_scenario == null) return "ERR:시나리오 없음";
569→
570→        if (_currentStepIndex >= _scenario.Operations.Count)
571→        {
572→            _scenarioRunning = false;
573→            Log("시나리오", "전체 완료 (DONE)");
574→            ScenarioCompleted?.Invoke();
575→            return "DONE";
576→        }
577→
578→        var op = _scenario.Operations[_currentStepIndex];
579→        Log("시나리오", $"스텝 {_currentStepIndex + 1}/{_scenario.Operations.Count} → col={op.Col}, row={op.Row}");
580→        StepStarted?.Invoke(_currentStepIndex, op);
581→
582→        return $"OK:{op.Col},{op.Row}";
583→    }
584→
585→    #endregion
586→
587→    #region Busy 폴링
588→
589→    /// <summary>
590→    /// 동작 완료 대기 (busy 폴링)
591→    /// </summary>
592→    private async Task<bool> WaitUntilDone(double timeout = BUSY_TIMEOUT_SEC, bool waitStart = false)
593→    {
594→        if (waitStart)
595→        {
596→            // busy=true 시작 대기 (최대 3초)
597→            var sw = System.Diagnostics.Stopwatch.StartNew();
598→            while (sw.Elapsed.TotalSeconds < 3)
599→            {
600→                try
601→                {
602→                    if (await CbClient.GetBusyAsync()) break;
603→                }
604→                catch { }
605→                await Task.Delay(50);
606→            }
607→        }
608→
609→        // busy=false 대기
610→        var sw2 = System.Diagnostics.Stopwatch.StartNew();
611→        while (sw2.Elapsed.TotalSeconds < timeout)
612→        {
613→            try
614→            {
615→                if (!await CbClient.GetBusyAsync()) return true;
616→            }
617→            catch { }
618→            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
619→        }
620→        return false;
621→    }
622→
623→    /// <summary>
624→    /// 샹크 자동 후퇴 완료 대기
625→    /// </summary>
626→    private async Task WaitRetract()
627→    {
628→        await Task.Delay(500);
629→        var sw = System.Diagnostics.Stopwatch.StartNew();
630→        while (sw.Elapsed.TotalSeconds < 10)
631→        {
632→            try
633→            {
634→                if (!await CbClient.GetBusyAsync()) return;
635→            }
636→            catch { }
637→            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
638→        }
639→    }
640→
641→    #endregion
642→}
