using System.IO;
using System.Net;
using System.Net.Sockets;
using System.Text;
using TmRobotEx.Scenario;
using TmRobotEx.WorkPlate;

namespace TmRobotEx.Bridge;

/// <summary>
/// TCP 5001 브릿지 서버.
/// sd_bridge.py의 C# 포팅.
/// TMscript(TCP) → 이 서버 → Compute Box(XML-RPC)
/// </summary>
public class BridgeServer
{
    private TcpListener? _listener;
    private CancellationTokenSource? _cts;
    private readonly int _port;
    private readonly SemaphoreSlim _cmdLock = new(1, 1);

    private const double BUSY_POLL_SEC = 0.1;
    private const double BUSY_TIMEOUT_SEC = 30;

    public ComputeBoxClient CbClient { get; }
    public WorkPlateData? PlateData { get; set; }

    // 시나리오 연동
    private ScrewScenario? _scenario;
    private int _currentStepIndex;
    private volatile bool _scenarioRunning;

    // 마지막 체결 결과 (tqDecision 용)
    private volatile bool _lastTightenOk;

    // next_step 블로킹 대기용
    private TaskCompletionSource<bool>? _scenarioReadyTcs;
    private readonly object _tcsLock = new();

    public event Action<string>? LogMessage;

    /// <summary>
    /// 스텝 시작 (stepIndex, operation) — TMflow가 next_step 요청 시
    /// </summary>
    public event Action<int, ScrewOperation>? StepStarted;

    /// <summary>
    /// 스텝 완료 (stepIndex, operation, success, achievedTorque) — TMflow가 step_result 보고 시
    /// </summary>
    public event Action<int, ScrewOperation, bool, double>? StepCompleted;

    /// <summary>
    /// 시나리오 전체 완료
    /// </summary>
    public event Action? ScenarioCompleted;

    public BridgeServer(int port, string cbUrl, int cbTimeout)
    {
        _port = port;
        CbClient = new ComputeBoxClient(cbUrl, cbTimeout);
        // CB 로그를 브릿지 로그로 전달
        CbClient.LogMessage += msg => LogMessage?.Invoke(msg);
    }

    private void Log(string tag, string msg) => LogMessage?.Invoke($"[{tag}] {msg}");

    /// <summary>
    /// 시나리오 실행 모드 시작 (TMflow 대기)
    /// </summary>
    public void StartScenario(ScrewScenario scenario)
    {
        _scenario = scenario;
        _currentStepIndex = 0;
        _scenarioRunning = true;
        Log("시나리오", $"시작: {scenario.Name} ({scenario.Operations.Count}개 스텝)");

        // 블로킹 대기 중인 next_step 요청 깨우기
        lock (_tcsLock)
        {
            _scenarioReadyTcs?.TrySetResult(true);
            _scenarioReadyTcs = null;
        }
    }

    /// <summary>
    /// 시나리오 실행 모드 정지
    /// </summary>
    public void StopScenario()
    {
        _scenarioRunning = false;
        _scenario = null;
        Log("시나리오", "중지");

        // 블로킹 대기 중인 next_step 요청 취소
        lock (_tcsLock)
        {
            _scenarioReadyTcs?.TrySetResult(false);
            _scenarioReadyTcs = null;
        }
    }

    public bool IsScenarioRunning => _scenarioRunning;

    /// <summary>
    /// UI에서 직접 명령 실행 (브릿지 디스패처 경유)
    /// </summary>
    public Task<string> ExecuteAsync(string cmdLine) => DispatchAsync(cmdLine);

    public Task StartAsync()
    {
        _cts = new CancellationTokenSource();
        _listener = new TcpListener(IPAddress.Any, _port);
        _listener.Server.SetSocketOption(
            System.Net.Sockets.SocketOptionLevel.Socket,
            System.Net.Sockets.SocketOptionName.ReuseAddress, true);
        _listener.Start();
        Log("서버", $"대기 중 — 0.0.0.0:{_port}");

        // 수신 루프 (백그라운드)
        _ = Task.Run(() => AcceptLoop(_cts.Token));

        // Compute Box 연결 확인 (백그라운드, 서버 시작 후)
        _ = Task.Run(CheckComputeBoxAsync);

        return Task.CompletedTask;
    }

    private async Task CheckComputeBoxAsync()
    {
        Log("초기화", $"Compute Box ({CbClient.Url}) 연결 중...");
        try
        {
            var busy = await CbClient.GetBusyAsync();
            var torque = await CbClient.GetTorqueAsync();
            var error = await CbClient.GetErrorCodeAsync();
            Log("초기화", "Compute Box 연결 OK");
            Log("초기화", $"  busy={Convert.ToInt32(busy)}  torque={torque:F2}  error={error}");
        }
        catch (Exception ex)
        {
            Log("오류", $"Compute Box 연결 실패: {ex.Message}");
            Log("오류", "Compute Box 전원/네트워크 확인 후 재시도");
        }
    }

    public void Stop()
    {
        Log("서버", "종료 중...");
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        try { _listener?.Stop(); } catch { }
        _listener = null;
        CbClient.Dispose();

        lock (_tcsLock)
        {
            _scenarioReadyTcs?.TrySetResult(false);
            _scenarioReadyTcs = null;
        }
        Log("서버", "종료 완료");
    }

    private async Task AcceptLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                var client = await _listener!.AcceptTcpClientAsync(token);
                var addr = ((IPEndPoint)client.Client.RemoteEndPoint!).Address;
                Log("연결", $"{addr} 접속");
                _ = Task.Run(() => HandleClient(client, addr.ToString(), token));
            }
            catch (OperationCanceledException) { break; }
            catch (Exception ex)
            {
                if (!token.IsCancellationRequested)
                    Log("오류", $"Accept 오류: {ex.Message}");
            }
        }
    }

    private async Task HandleClient(TcpClient client, string addr, CancellationToken token)
    {
        using (client)
        {
            try
            {
                client.ReceiveTimeout = 60000;
                using var stream = client.GetStream();
                // BOM 없는 UTF-8 (파이썬 브릿지와 동일)
                var utf8 = new UTF8Encoding(false);
                using var reader = new StreamReader(stream, utf8, detectEncodingFromByteOrderMarks: false);

                while (!token.IsCancellationRequested)
                {
                    string? line;
                    try
                    {
                        line = await reader.ReadLineAsync(token);
                    }
                    catch { break; }

                    if (line == null) break;

                    line = line.Trim();
                    if (string.IsNullOrEmpty(line)) continue;

                    Log("수신", $"{addr} > {line}");
                    var t0 = DateTime.Now;

                    string result;
                    try
                    {
                        result = await DispatchAsync(line);
                    }
                    catch (Exception ex)
                    {
                        result = $"ERR:{ex.Message}";
                        Log("오류", $"처리 중 예외: {ex.Message}");
                    }

                    var ms = (DateTime.Now - t0).TotalMilliseconds;
                    Log("응답", $"{addr} < {result}  ({ms:F0}ms)");

                    // 파이썬과 동일: result + \r\n, 바이트로 직접 전송
                    try
                    {
                        var responseBytes = utf8.GetBytes(result + "\r\n");
                        await stream.WriteAsync(responseBytes, token);
                        await stream.FlushAsync(token);
                    }
                    catch { break; }
                }
            }
            catch (OperationCanceledException) { }
            catch (Exception ex)
            {
                if (!token.IsCancellationRequested)
                    Log("오류", $"{addr} 핸들러 예외: {ex.Message}");
            }
            finally
            {
                Log("종료", $"{addr} 연결 끊김");
            }
        }
    }

    /// <summary>
    /// 명령 디스패처 (SemaphoreSlim으로 직렬화)
    /// </summary>
    private async Task<string> DispatchAsync(string cmdLine)
    {
        var parts = cmdLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        if (parts.Length == 0) return "ERR:빈 명령";

        var cmd = parts[0].ToLower();
        var args = parts[1..];

        // next_step은 블로킹 대기하므로 cmdLock 밖에서 처리
        if (cmd == "next_step")
        {
            try { return await CmdNextStepAsync(); }
            catch (Exception ex)
            {
                Log("오류", $"dispatch 예외: {ex.Message}");
                return $"ERR:{ex.Message}";
            }
        }

        await _cmdLock.WaitAsync();
        try
        {
            return cmd switch
            {
                "config" => await CmdConfig(args),
                "pickup" => await CmdPickup(args),
                "tighten" => await CmdTighten(args),
                "loosen" => await CmdLoosen(args),
                "shank" => await CmdShank(args),
                "stop" => await CmdStop(),
                "status" => await CmdStatus(),
                "recover" => await CmdRecover(),
                "raw" => await CmdRaw(args),
                "next_hole" => CmdNextHole(),
                "hole_result" => CmdHoleResult(args),
                "get_coord" => CmdGetCoord(args),
                "tqdecision" => CmdTqDecision(),
                _ => $"ERR:unknown '{cmd}'"
            };
        }
        catch (Exception ex)
        {
            Log("오류", $"dispatch 예외: {ex.Message}");
            return $"ERR:{ex.Message}";
        }
        finally
        {
            _cmdLock.Release();
        }
    }

    #region 기본 명령 (sd_bridge.py 동일)

    private async Task<string> CmdConfig(string[] args)
    {
        double extender = args.Length > 0 && double.TryParse(args[0], out var e) ? e : 0;
        await CbClient.ConfigAsync(extender);
        return $"OK:config extender={extender}";
    }

    private async Task<string> CmdPickup(string[] args)
    {
        if (args.Length < 2) return "ERR:pickup <force_N> <len_mm>";
        int force = int.Parse(args[0]);
        double length = double.Parse(args[1]);

        await CbClient.PickupScrewAsync(force, length);
        var done = await WaitUntilDone(waitStart: true);
        var error = await CbClient.GetErrorCodeAsync();
        if (!done) return $"ERR:pickup timeout,error={error}";
        if (error != 0) return $"ERR:pickup error={error}";
        return "OK:pickup";
    }

    private async Task<string> CmdTighten(string[] args)
    {
        if (args.Length < 3) return "ERR:tighten <force_N> <len_mm> <torque_Nm>";
        int force = int.Parse(args[0]);
        double length = double.Parse(args[1]);
        double torque = double.Parse(args[2]);

        await CbClient.TightenAsync(force, length, torque);
        var done = await WaitUntilDone(waitStart: true);
        var achieved = await CbClient.GetTorqueAsync();
        var error = await CbClient.GetErrorCodeAsync();

        bool success;
        string response;
        if (!done)
        {
            success = false;
            response = $"ERR:tighten timeout,torque={achieved:F2},error={error}";
        }
        else if (error != 0)
        {
            success = false;
            response = $"ERR:tighten error={error},torque={achieved:F2}";
        }
        else if (achieved < 0.15)
        {
            // 토크 부족 → NG (재시도 필요)
            success = false;
            await WaitRetract();
            response = $"OK:tighten torque={achieved:F2}";
        }
        else
        {
            success = true;
            await WaitRetract();
            response = $"OK:tighten torque={achieved:F2}";
        }

        _lastTightenOk = success;

        // 시나리오 실행 중이면 결과 기록 + 성공 시만 스텝 진행
        if (_scenarioRunning && _scenario != null && _currentStepIndex < _scenario.Operations.Count)
        {
            var op = _scenario.Operations[_currentStepIndex];
            var status = success ? HoleStatus.Ok : HoleStatus.Ng;
            PlateData?.SetResult(op.Col, op.Row, status, achieved);

            Log("시나리오", $"스텝 {_currentStepIndex + 1} 결과: {(success ? "OK" : "NG")}, torque={achieved:F2}");
            StepCompleted?.Invoke(_currentStepIndex, op, success, achieved);

            // NG면 스텝 진행 안 함 (next_step에서 같은 홀 반환 → 재시도)
            if (!success)
            {
                Log("시나리오", $"스텝 {_currentStepIndex + 1} 재시도 필요 (torque={achieved:F2} < 0.15)");
                return response;
            }

            _currentStepIndex++;

            if (_currentStepIndex >= _scenario.Operations.Count)
            {
                _scenarioRunning = false;
                Log("시나리오", $"전체 완료 ({_scenario.Operations.Count}개 스텝)");
                ScenarioCompleted?.Invoke();
            }
        }

        return response;
    }

    private async Task<string> CmdLoosen(string[] args)
    {
        if (args.Length < 2) return "ERR:loosen <force_N> <len_mm>";
        int force = int.Parse(args[0]);
        double length = double.Parse(args[1]);

        await CbClient.LoosenAsync(force, length);
        var done = await WaitUntilDone(waitStart: true);
        var error = await CbClient.GetErrorCodeAsync();
        if (!done) return $"ERR:loosen timeout,error={error}";
        if (error != 0) return $"ERR:loosen error={error}";
        await WaitRetract();
        return "OK:loosen";
    }

    private async Task<string> CmdShank(string[] args)
    {
        if (args.Length < 1) return "ERR:shank <pos> (0=후퇴, 55=전진)";
        int pos = int.Parse(args[0]);
        await CbClient.MoveShankAsync(pos);
        return "OK:shank";
    }

    private async Task<string> CmdStop()
    {
        await CbClient.StopAsync();
        return "OK:stop";
    }

    private async Task<string> CmdStatus()
    {
        var error = await CbClient.GetErrorCodeAsync();
        var safety = await CbClient.GetZSafetyActivatedAsync();

        if (error != 0 || safety)
        {
            Log("복구", $"에러/안전 감지 (error={error}, safety={safety}), 자동 복구...");
            await CbClient.MoveShankAsync(0);
            await Task.Delay(3000);
            await WaitUntilDone(timeout: 10);

            var error2 = await CbClient.GetErrorCodeAsync();
            var safety2 = await CbClient.GetZSafetyActivatedAsync();
            if (error2 == 0 && !safety2)
                Log("복구", "복구 완료");
            else
                Log("복구", $"복구 실패 (error={error2}, safety={safety2})");
        }

        var busy = await CbClient.GetBusyAsync();
        var torque = await CbClient.GetTorqueAsync();
        error = await CbClient.GetErrorCodeAsync();
        return $"OK:busy={Convert.ToInt32(busy)},torque={torque:F2},error={error}";
    }

    private async Task<string> CmdRecover()
    {
        Log("복구", "수동 복구 시작 (샹크 후퇴)...");
        await CbClient.MoveShankAsync(0);
        await Task.Delay(3000);
        await WaitUntilDone(timeout: 10);
        var error = await CbClient.GetErrorCodeAsync();
        var safety = await CbClient.GetZSafetyActivatedAsync();
        if (error == 0 && !safety)
        {
            Log("복구", "복구 완료");
            return "OK:recover";
        }
        Log("복구", $"복구 실패 (error={error}, safety={safety})");
        return $"ERR:recover error={error},safety={Convert.ToInt32(safety)}";
    }

    private async Task<string> CmdRaw(string[] args)
    {
        if (args.Length == 0) return "ERR:raw <method> [args...]";
        var method = args[0];
        var callArgs = new object[args.Length - 1];
        for (int i = 1; i < args.Length; i++)
        {
            if (int.TryParse(args[i], out var iv)) callArgs[i - 1] = iv;
            else if (double.TryParse(args[i], out var dv)) callArgs[i - 1] = dv;
            else callArgs[i - 1] = args[i];
        }
        var result = await CbClient.CallRawAsync(method, callArgs);
        return $"OK:{result}";
    }

    #endregion

    #region 확장 명령 (시나리오 연동)

    private string CmdNextHole()
    {
        if (PlateData == null) return "ERR:작업판 없음";
        var next = PlateData.GetNextEmpty();
        if (next == null) return "ERR:빈 홀 없음";
        return $"OK:{next.Value.col},{next.Value.row}";
    }

    private string CmdHoleResult(string[] args)
    {
        if (PlateData == null) return "ERR:작업판 없음";
        if (args.Length < 4) return "ERR:hole_result <col> <row> <ok|ng> <torque>";
        int col = int.Parse(args[0]);
        int row = int.Parse(args[1]);
        var status = args[2].ToLower() == "ok" ? HoleStatus.Ok : HoleStatus.Ng;
        double torque = double.Parse(args[3]);
        PlateData.SetResult(col, row, status, torque);
        return "OK:hole_result";
    }

    private string CmdGetCoord(string[] args)
    {
        if (PlateData == null) return "ERR:작업판 없음";
        if (args.Length < 2) return "ERR:get_coord <col> <row>";
        int col = int.Parse(args[0]);
        int row = int.Parse(args[1]);
        // 20mm 피치 기준 좌표 (원점은 (0,0) 홀)
        double x = col * 20.0;
        double y = row * 20.0;
        return $"OK:{x:F1},{y:F1}";
    }

    /// <summary>
    /// 마지막 체결 결과 반환 (OK 또는 NG)
    /// </summary>
    private string CmdTqDecision()
    {
        return _lastTightenOk ? "OK" : "NG";
    }

    #endregion

    #region 시나리오 연동 명령

    /// <summary>
    /// TMflow → next_step: 다음 작업 스텝의 col,row 반환
    /// 시나리오 미실행 시 시작될 때까지 블로킹 대기 (최대 60초)
    /// 응답: OK:col,row  또는  DONE  또는  ERR:...
    /// </summary>
    private async Task<string> CmdNextStepAsync()
    {
        // 시나리오 완료 상태 → 즉시 DONE 반환
        if (!_scenarioRunning && _scenario != null && _currentStepIndex >= _scenario.Operations.Count)
        {
            return "DONE";
        }

        // 시나리오 미실행 → 시작될 때까지 대기
        if (!_scenarioRunning || _scenario == null)
        {
            Log("시나리오", "next_step 대기 중 (PC에서 실행 버튼 대기)...");

            TaskCompletionSource<bool> tcs;
            lock (_tcsLock)
            {
                _scenarioReadyTcs ??= new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
                tcs = _scenarioReadyTcs;
            }

            // 시나리오 시작 또는 서버 종료까지 무한 대기
            await tcs.Task;

            if (!tcs.Task.Result)
            {
                return "ERR:시나리오 취소";
            }

            Log("시나리오", "시나리오 시작 신호 수신");
        }

        if (_scenario == null) return "ERR:시나리오 없음";

        if (_currentStepIndex >= _scenario.Operations.Count)
        {
            _scenarioRunning = false;
            Log("시나리오", "전체 완료 (DONE)");
            ScenarioCompleted?.Invoke();
            return "DONE";
        }

        var op = _scenario.Operations[_currentStepIndex];
        Log("시나리오", $"스텝 {_currentStepIndex + 1}/{_scenario.Operations.Count} → col={op.Col}, row={op.Row}");
        StepStarted?.Invoke(_currentStepIndex, op);

        return $"OK:{op.Col},{op.Row}";
    }

    #endregion

    #region Busy 폴링

    /// <summary>
    /// 동작 완료 대기 (busy 폴링)
    /// </summary>
    private async Task<bool> WaitUntilDone(double timeout = BUSY_TIMEOUT_SEC, bool waitStart = false)
    {
        if (waitStart)
        {
            // busy=true 시작 대기 (최대 3초)
            var sw = System.Diagnostics.Stopwatch.StartNew();
            while (sw.Elapsed.TotalSeconds < 3)
            {
                try
                {
                    if (await CbClient.GetBusyAsync()) break;
                }
                catch { }
                await Task.Delay(50);
            }
        }

        // busy=false 대기
        var sw2 = System.Diagnostics.Stopwatch.StartNew();
        while (sw2.Elapsed.TotalSeconds < timeout)
        {
            try
            {
                if (!await CbClient.GetBusyAsync()) return true;
            }
            catch { }
            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
        }
        return false;
    }

    /// <summary>
    /// 샹크 자동 후퇴 완료 대기
    /// </summary>
    private async Task WaitRetract()
    {
        await Task.Delay(500);
        var sw = System.Diagnostics.Stopwatch.StartNew();
        while (sw.Elapsed.TotalSeconds < 10)
        {
            try
            {
                if (!await CbClient.GetBusyAsync()) return;
            }
            catch { }
            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
        }
    }

    #endregion
}

