693→    /// <summary>
694→    /// 단위 구체 메시 생성 (반지름 1, 원점 중심)
695→    /// </summary>
696→    private static MeshGeometry3D CreateUnitSphereMesh(int thetaDiv = 8, int phiDiv = 5)
697→    {
698→        var mesh = new MeshGeometry3D();
699→        for (int pi = 0; pi <= phiDiv; pi++)
700→        {
701→            double phi = Math.PI * pi / phiDiv;
702→            for (int ti = 0; ti <= thetaDiv; ti++)
703→            {
704→                double theta = 2 * Math.PI * ti / thetaDiv;
705→                double x = Math.Sin(phi) * Math.Cos(theta);
706→                double y = Math.Sin(phi) * Math.Sin(theta);
707→                double z = Math.Cos(phi);
708→                mesh.Positions.Add(new Point3D(x, y, z));
709→                mesh.Normals.Add(new Vector3D(x, y, z));
710→            }
711→        }
712→        for (int pi = 0; pi < phiDiv; pi++)
713→        {
714→            for (int ti = 0; ti < thetaDiv; ti++)
715→            {
716→                int i0 = pi * (thetaDiv + 1) + ti;
717→                int i1 = i0 + 1;
718→                int i2 = i0 + thetaDiv + 1;
719→                int i3 = i2 + 1;
720→                mesh.TriangleIndices.Add(i0);
721→                mesh.TriangleIndices.Add(i2);
722→                mesh.TriangleIndices.Add(i1);
723→                mesh.TriangleIndices.Add(i1);
724→                mesh.TriangleIndices.Add(i2);
725→                mesh.TriangleIndices.Add(i3);
726→            }
727→        }
728→        mesh.Freeze();
729→        return mesh;
730→    }
