732→    private void Build3DWorkPlate()
733→    {
734→        // 3D 모델 좌표 직접 사용 (FK 오프셋 불필요)
735→        var p1 = CalP1;
736→        var p2 = CalP2;
737→        var p3 = CalP3;
738→
739→        // 그리드 벡터
740→        var rowStep = (p2 - p1) / (WorkPlateData.ROWS - 1);  // 15행, 14 간격
741→        var colStep = (p3 - p2) / (WorkPlateData.COLS - 1);  // 9열, 8 간격
742→
743→        // 공유 구체 메시 (반지름 5mm 스케일 적용)
744→        var sphereMesh = CreateUnitSphereMesh();
745→        var group = new Model3DGroup();
746→        var yellowBrush = new SolidColorBrush(Color.FromRgb(255, 204, 0));
747→
748→        // 135개 홀
749→        for (int r = 0; r < WorkPlateData.ROWS; r++)
750→        {
751→            for (int c = 0; c < WorkPlateData.COLS; c++)
752→            {
753→                var pos = p1 + r * rowStep + c * colStep;
754→                var tg = new Transform3DGroup();
755→                tg.Children.Add(new ScaleTransform3D(5, 5, 5));
756→                tg.Children.Add(new TranslateTransform3D(pos.X, pos.Y, pos.Z));
757→
758→                var model = new GeometryModel3D
759→                {
760→                    Geometry = sphereMesh,
761→                    Material = Mat3DEmpty,
762→                    BackMaterial = Mat3DEmpty,
763→                    Transform = tg
764→                };
765→                _hole3D[r * WorkPlateData.COLS + c] = model;
766→                group.Children.Add(model);
767→            }
768→        }
769→
770→        _plate3DVisual = new ModelVisual3D { Content = group };
771→        Viewport3D.Children.Add(_plate3DVisual);
772→
773→        // 테두리선 (노란색)
774→        var p00 = p1;
775→        var pR0 = p1 + (WorkPlateData.ROWS - 1) * rowStep;
776→        var p0C = p1 + (WorkPlateData.COLS - 1) * colStep;
777→        var pRC = p1 + (WorkPlateData.ROWS - 1) * rowStep + (WorkPlateData.COLS - 1) * colStep;
778→
779→        _plateBorder = new LinesVisual3D
780→        {
781→            Color = Colors.Yellow,
782→            Thickness = 2,
783→            Points = new Point3DCollection(new[] { p00, pR0, pR0, pRC, pRC, p0C, p0C, p00 })
784→        };
785→        Viewport3D.Children.Add(_plateBorder);
786→
787→        // 코너 라벨
788→        Viewport3D.Children.Add(new BillboardTextVisual3D
789→        {
790→            Text = "(0,0)", Foreground = yellowBrush, FontSize = 11,
791→            Position = new Point3D(p00.X, p00.Y, p00.Z + 15)
792→        });
793→        Viewport3D.Children.Add(new BillboardTextVisual3D
794→        {
795→            Text = $"(0,{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
796→            Position = new Point3D(p0C.X, p0C.Y, p0C.Z + 15)
797→        });
798→        Viewport3D.Children.Add(new BillboardTextVisual3D
799→        {
800→            Text = $"({WorkPlateData.ROWS - 1},0)", Foreground = yellowBrush, FontSize = 11,
801→            Position = new Point3D(pR0.X, pR0.Y, pR0.Z + 15)
802→        });
803→        Viewport3D.Children.Add(new BillboardTextVisual3D
804→        {
805→            Text = $"({WorkPlateData.ROWS - 1},{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
806→            Position = new Point3D(pRC.X, pRC.Y, pRC.Z + 15)
807→        });
808→
809→    }
