812→    /// 3D 작업판 홀 색상 갱신 (WorkPlateData 상태 반영)
813→    /// </summary>
814→    private void Update3DPlate()
815→    {
816→        if (_plate3DVisual == null) return;
817→
818→        for (int r = 0; r < WorkPlateData.ROWS; r++)
819→        {
820→            for (int c = 0; c < WorkPlateData.COLS; c++)
821→            {
822→                var hole = _plateData.GetHole(c, r);
823→                var mat = hole.Status switch
824→                {
825→                    HoleStatus.Ok => Mat3DOk,
826→                    HoleStatus.Ng => Mat3DNg,
827→                    _ => Mat3DEmpty
828→                };
829→                var model = _hole3D[r * WorkPlateData.COLS + c];
830→                if (model.Material != mat)
831→                {
832→                    model.Material = mat;
833→                    model.BackMaterial = mat;
834→                }
835→            }
836→        }
837→    }
