using System.IO;
using System.Linq;
using System.Text.Json;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Media;
using System.Windows.Media.Media3D;
using HelixToolkit.Wpf;
using TmRobotEx.Bridge;
using TmRobotEx.Robot;
using TmRobotEx.Scenario;
using TmRobotEx.Settings;
using TmRobotEx.WorkPlate;

namespace TmRobotEx;

public partial class MainWindow : Window
{
    private readonly RobotModel _robotModel;
    private readonly TmRobotClient _robotClient;
    private BridgeServer? _bridgeServer;
    private readonly WorkPlateData _plateData;
    private readonly WorkPlatePanel _platePanel;
    private readonly AppSettings _settings;

    // 시나리오 편집
    private ScrewScenario _currentScenario = new() { Name = "새 시나리오" };

    // 갱신 주기 측정
    private DateTime _lastUpdateTime = DateTime.MinValue;
    private int _updateCount;

    // 최신 TCP 좌표 (X,Y,Z,Rx,Ry,Rz)
    private double[] _lastTcp = new double[6];
    private double[] _lastJoints = new double[6];
    // 작업판 3D 오버레이 (3D 모델 좌표 직접 측정, FK 오프셋 불필요)
    //   P1(0,0)→P2(14,0): 15행 방향 (14 간격, ~20mm 피치)
    //   P2(14,0)→P3(14,8): 9열 방향 (8 간격, ~20mm 피치)
    //   볼트: M3
    private static readonly Point3D CalP1 = new(833.5, 510.3, -56.9);   // (0,0)
    private static readonly Point3D CalP2 = new(625.8, 323.3, -62.0);   // (14,0)
    private static readonly Point3D CalP3 = new(731.3, 203.6, -63.4);   // (14,8)

    private readonly GeometryModel3D[] _hole3D = new GeometryModel3D[WorkPlateData.COLS * WorkPlateData.ROWS];
    private ModelVisual3D? _plate3DVisual;
    private LinesVisual3D? _plateBorder;

    private static readonly DiffuseMaterial Mat3DEmpty = new(new SolidColorBrush(Color.FromArgb(180, 120, 120, 120)));
    private static readonly DiffuseMaterial Mat3DOk = new(new SolidColorBrush(Color.FromArgb(230, 80, 200, 80)));
    private static readonly DiffuseMaterial Mat3DNg = new(new SolidColorBrush(Color.FromArgb(230, 220, 60, 60)));
    private static readonly DiffuseMaterial Mat3DCurrent = new(new SolidColorBrush(Color.FromArgb(255, 255, 220, 0)));

    // 캐시된 UI 브러시 (Freeze → 스레드 안전)
    private static readonly SolidColorBrush BrGreen = Frozen(Color.FromRgb(0x60, 0xC0, 0x60));
    private static readonly SolidColorBrush BrGray = Frozen(Color.FromRgb(0x66, 0x66, 0x66));
    private static readonly SolidColorBrush BrRed = Frozen(Color.FromRgb(0xE0, 0x40, 0x40));
    private static readonly SolidColorBrush BrTxtGreen = Frozen(Color.FromRgb(0x90, 0xC0, 0x90));
    private static readonly SolidColorBrush BrTxtGray = Frozen(Color.FromRgb(0x90, 0x90, 0x90));
    private static readonly SolidColorBrush BrYellow = Frozen(Color.FromRgb(0xE0, 0xC0, 0x40));
    private static readonly SolidColorBrush BrCyan = Frozen(Color.FromRgb(0x60, 0xC0, 0xE0));
    private static readonly SolidColorBrush BrIndRed = Frozen(Color.FromRgb(0xC0, 0x60, 0x60));
    private static readonly SolidColorBrush BrTxtRed = Frozen(Color.FromRgb(0xC0, 0x90, 0x90));
    private static SolidColorBrush Frozen(Color c) { var b = new SolidColorBrush(c); b.Freeze(); return b; }

    // 로그 파일
    private static readonly string LogFilePath = Path.Combine(
        AppDomain.CurrentDomain.BaseDirectory, "app.log");
    private int _logWriteCount;

    public MainWindow()
    {
        InitializeComponent();

        // 설정 로드
        _settings = AppSettings.Load();

        // 로봇 3D 모델
        _robotModel = new RobotModel();
        Viewport3D.Children.Add(_robotModel.RootVisual);

        // 로봇 TCP 클라이언트
        _robotClient = new TmRobotClient
        {
            Host = _settings.RobotHost,
            Port = _settings.RobotPort
        };
        _robotClient.DataReceived += OnRobotDataReceived;
        _robotClient.ConnectionChanged += OnRobotConnectionChanged;
        _robotClient.LogMessage += msg => Dispatcher.Invoke(() => AddLog($"[로봇] {msg}"));

        // 작업판
        _plateData = new WorkPlateData();
        _platePanel = new WorkPlatePanel(_plateData, WorkPlateCanvas);
        _platePanel.HoleClicked += OnHoleClicked;

        AddLog("TmRobot Ex 시작");

        Loaded += async (_, _) =>
        {
            SetDefaultCamera();
            _platePanel.Render();
            UpdatePlateStats();
            Update3DPlate();
            Build3DWorkPlate();
            RefreshScenarioComboBox();

            // 자동 연결: 로봇 + 브릿지
            await AutoStartAsync();
        };
    }

    #region 자동 시작

    private async Task AutoStartAsync()
    {
        // 브릿지 서버 자동 시작
        MenuBridgeStart_Click(this, new RoutedEventArgs());
        await Task.Delay(500);

        // 로봇 자동 연결
        MenuRobotConnect_Click(this, new RoutedEventArgs());
    }

    #endregion

    #region 카메라

    private void SetDefaultCamera()
    {
        var cam = Viewport3D.Camera as PerspectiveCamera;
        if (cam == null) return;

        var target = new Point3D(349.2, 424.3, 62.9);
        var cameraPos = new Point3D(1756.9, 108.0, 640.5);

        cam.Position = cameraPos;
        cam.LookDirection = target - cameraPos;
        cam.UpDirection = new Vector3D(-0.068, 0.015, 0.998);
        cam.FieldOfView = 45;

        Viewport3D.CameraController!.CameraTarget = target;
    }

    #endregion

    #region 로봇 연결

    private async void MenuRobotConnect_Click(object sender, RoutedEventArgs e)
    {
        _robotClient.Host = _settings.RobotHost;
        _robotClient.Port = _settings.RobotPort;
        await _robotClient.ConnectAsync();
    }

    private void MenuRobotDisconnect_Click(object sender, RoutedEventArgs e)
    {
        _robotClient.Disconnect();
    }

    private void OnRobotDataReceived(double[] joints, double[] tcp)
    {
        Dispatcher.Invoke(() =>
        {
            _robotModel.SetAllJointAngles(joints);
            Array.Copy(tcp, _lastTcp, Math.Min(tcp.Length, 6));
            Array.Copy(joints, _lastJoints, Math.Min(joints.Length, 6));

            // 갱신 주기
            _updateCount++;
            var now = DateTime.Now;
            var elapsed = (now - _lastUpdateTime).TotalSeconds;
            if (elapsed >= 1.0)
            {
                TxtUpdateRate.Text = $"갱신: {_updateCount / elapsed:F1} Hz";
                _updateCount = 0;
                _lastUpdateTime = now;
            }
        });
    }

    private void OnRobotConnectionChanged(bool connected, string message)
    {
        Dispatcher.Invoke(() =>
        {
            if (connected)
            {
                IndRobot.Fill = BrGreen;
                TxtStatusRobot.Text = $"로봇: {message}";
                TxtStatusRobot.Foreground = BrTxtGreen;
                _lastUpdateTime = DateTime.Now;
                _updateCount = 0;
            }
            else
            {
                IndRobot.Fill = BrGray;
                TxtStatusRobot.Text = "로봇: 미연결";
                TxtStatusRobot.Foreground = BrTxtGray;
                TxtUpdateRate.Text = "갱신: -";
            }
        });
    }

    #endregion

    #region 브릿지 서버

    private async void MenuBridgeStart_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer != null) return;

        try
        {
            _bridgeServer = new BridgeServer(_settings.BridgePort, _settings.ComputeBoxUrl, _settings.ComputeBoxTimeout);
            _bridgeServer.LogMessage += msg =>
            {
                System.Diagnostics.Debug.WriteLine($"[Bridge] {msg}");
                Dispatcher.BeginInvoke(() => AddLog(msg));
            };

            // 확장 명령 연동: 작업판 데이터 제공
            _bridgeServer.PlateData = _plateData;

            // 시나리오 연동 이벤트
            _bridgeServer.StepStarted += OnBridgeStepStarted;
            _bridgeServer.StepCompleted += OnBridgeStepCompleted;
            _bridgeServer.ScenarioCompleted += OnBridgeScenarioCompleted;

            await _bridgeServer.StartAsync();

            IndBridge.Fill = BrGreen;
            TxtStatusBridge.Text = $"브릿지: 포트 {_settings.BridgePort}";
            TxtStatusBridge.Foreground = BrTxtGreen;
            // 브릿지 시작 로그는 BridgeServer.StartAsync()에서 출력

            // CB 연결 확인
            _ = CheckComputeBoxAsync();
        }
        catch (Exception ex)
        {
            AddLog($"브릿지 시작 실패: {ex.Message}");
            _bridgeServer = null;
        }
    }

    private void MenuBridgeStop_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer == null) return;

        _bridgeServer.Stop();
        _bridgeServer = null;

        IndBridge.Fill = BrGray;
        TxtStatusBridge.Text = "브릿지: 중지";
        TxtStatusBridge.Foreground = BrTxtGray;
        IndCb.Fill = BrGray;
        TxtStatusCb.Text = "CB: 미연결";
        TxtStatusCb.Foreground = BrTxtGray;
        AddLog("브릿지 서버 중지");
    }

    private async Task CheckComputeBoxAsync()
    {
        if (_bridgeServer == null) return;
        try
        {
            await _bridgeServer.CbClient.GetBusyAsync();
            Dispatcher.Invoke(() =>
            {
                IndCb.Fill = BrGreen;
                TxtStatusCb.Text = "CB: 연결됨";
                TxtStatusCb.Foreground = BrTxtGreen;
            });
        }
        catch
        {
            Dispatcher.Invoke(() =>
            {
                IndCb.Fill = BrIndRed;
                TxtStatusCb.Text = "CB: 연결 실패";
                TxtStatusCb.Foreground = BrTxtRed;
            });
        }
    }

