    private void OnBridgeStepStarted(int stepIndex, ScrewOperation op)
    {
        Dispatcher.Invoke(() =>
        {
            TxtScenarioStatus.Text = $"실행 중: {stepIndex + 1}/{_currentScenario.Operations.Count} — 홀({op.Col},{op.Row}) {op.Command}";
            TxtScenarioStatus.Foreground = BrCyan;
            LstScenario.SelectedIndex = stepIndex;
            _platePanel.HighlightHole(op.Col, op.Row);
        });
    }

    private void OnBridgeStepCompleted(int stepIndex, ScrewOperation op, bool success, double torque)
    {
        Dispatcher.Invoke(() =>
        {
            var status = success ? HoleStatus.Ok : HoleStatus.Ng;
            _plateData.SetResult(op.Col, op.Row, status, torque);
            _platePanel.Render();
            UpdatePlateStats();
            Update3DPlate();
            AddLog($"[{stepIndex + 1}] 홀({op.Col},{op.Row}) {(success ? "OK" : "NG")} torque={torque:F2}");

            // 토크 모니터 그리드에 누적 (0.15 미만 빨간색)
            var color = torque >= 0.15
                ? BrGreen
                : BrRed;
            LvTorque.Items.Add(new
            {
                No = stepIndex + 1,
                Hole = $"({op.Col},{op.Row})",
                Torque = torque.ToString("F2"),
                TorqueColor = color
            });
            while (LvTorque.Items.Count > 500)
                LvTorque.Items.RemoveAt(0);
            LvTorque.ScrollIntoView(LvTorque.Items[^1]);
        });
    }

