    private void RefreshScenarioComboBox()
    {
        LoadScenariosFile();
        var selected = CmbScenario.SelectedItem as string;
        CmbScenario.Items.Clear();

        foreach (var s in _savedScenarios)
            CmbScenario.Items.Add(s.Name);

