    private static readonly JsonSerializerOptions _scenJsonOpts = new()
    {
        WriteIndented = true,
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    private void LoadScenariosFile()
    {
        if (!File.Exists(ScenariosFile)) { _savedScenarios = []; return; }
        try
        {
            var json = File.ReadAllText(ScenariosFile);
            _savedScenarios = JsonSerializer.Deserialize<List<ScrewScenario>>(json, _scenJsonOpts) ?? [];
        }
        catch { _savedScenarios = []; }
    }

    private void SaveScenariosFile()
    {
        var json = JsonSerializer.Serialize(_savedScenarios, _scenJsonOpts);
        File.WriteAllText(ScenariosFile, json);
    }

