    #region 작업판 3D 오버레이

    /// <summary>
    /// 3D 작업판 재생성
    /// </summary>
    private void Rebuild3DWorkPlate()
    {
        if (_plate3DVisual != null)
            Viewport3D.Children.Remove(_plate3DVisual);
        if (_plateBorder != null)
            Viewport3D.Children.Remove(_plateBorder);

        var toRemove = Viewport3D.Children
            .OfType<BillboardTextVisual3D>()
            .Where(b => b.Text.StartsWith("("))
            .ToList();
        foreach (var b in toRemove)
            Viewport3D.Children.Remove(b);

        Build3DWorkPlate();
    }

    /// <summary>
    /// 단위 구체 메시 생성 (반지름 1, 원점 중심)
    /// </summary>
    private static MeshGeometry3D CreateUnitSphereMesh(int thetaDiv = 8, int phiDiv = 5)
    {
        var mesh = new MeshGeometry3D();
        for (int pi = 0; pi <= phiDiv; pi++)
        {
            double phi = Math.PI * pi / phiDiv;
            for (int ti = 0; ti <= thetaDiv; ti++)
            {
                double theta = 2 * Math.PI * ti / thetaDiv;
                double x = Math.Sin(phi) * Math.Cos(theta);
                double y = Math.Sin(phi) * Math.Sin(theta);
                double z = Math.Cos(phi);
                mesh.Positions.Add(new Point3D(x, y, z));
                mesh.Normals.Add(new Vector3D(x, y, z));
            }
        }
        for (int pi = 0; pi < phiDiv; pi++)
        {
            for (int ti = 0; ti < thetaDiv; ti++)
            {
                int i0 = pi * (thetaDiv + 1) + ti;
                int i1 = i0 + 1;
                int i2 = i0 + thetaDiv + 1;
                int i3 = i2 + 1;
                mesh.TriangleIndices.Add(i0);
                mesh.TriangleIndices.Add(i2);
                mesh.TriangleIndices.Add(i1);
                mesh.TriangleIndices.Add(i1);
                mesh.TriangleIndices.Add(i2);
                mesh.TriangleIndices.Add(i3);
            }
        }
        mesh.Freeze();
        return mesh;
    }

    private void Build3DWorkPlate()
    {
        // 3D 모델 좌표 직접 사용 (FK 오프셋 불필요)
        var p1 = CalP1;
        var p2 = CalP2;
        var p3 = CalP3;

        // 그리드 벡터
        var rowStep = (p2 - p1) / (WorkPlateData.ROWS - 1);  // 15행, 14 간격
        var colStep = (p3 - p2) / (WorkPlateData.COLS - 1);  // 9열, 8 간격

        // 공유 구체 메시 (반지름 5mm 스케일 적용)
        var sphereMesh = CreateUnitSphereMesh();
        var group = new Model3DGroup();
        var yellowBrush = new SolidColorBrush(Color.FromRgb(255, 204, 0));

        // 135개 홀
        for (int r = 0; r < WorkPlateData.ROWS; r++)
        {
            for (int c = 0; c < WorkPlateData.COLS; c++)
            {
                var pos = p1 + r * rowStep + c * colStep;
                var tg = new Transform3DGroup();
                tg.Children.Add(new ScaleTransform3D(5, 5, 5));
                tg.Children.Add(new TranslateTransform3D(pos.X, pos.Y, pos.Z));

                var model = new GeometryModel3D
                {
                    Geometry = sphereMesh,
                    Material = Mat3DEmpty,
                    BackMaterial = Mat3DEmpty,
                    Transform = tg
                };
                _hole3D[r * WorkPlateData.COLS + c] = model;
                group.Children.Add(model);
            }
        }

        _plate3DVisual = new ModelVisual3D { Content = group };
        Viewport3D.Children.Add(_plate3DVisual);

        // 테두리선 (노란색)
        var p00 = p1;
        var pR0 = p1 + (WorkPlateData.ROWS - 1) * rowStep;
        var p0C = p1 + (WorkPlateData.COLS - 1) * colStep;
        var pRC = p1 + (WorkPlateData.ROWS - 1) * rowStep + (WorkPlateData.COLS - 1) * colStep;

        _plateBorder = new LinesVisual3D
        {
            Color = Colors.Yellow,
            Thickness = 2,
            Points = new Point3DCollection(new[] { p00, pR0, pR0, pRC, pRC, p0C, p0C, p00 })
        };
        Viewport3D.Children.Add(_plateBorder);

        // 코너 라벨
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = "(0,0)", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(p00.X, p00.Y, p00.Z + 15)
        });
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = $"(0,{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(p0C.X, p0C.Y, p0C.Z + 15)
        });
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = $"({WorkPlateData.ROWS - 1},0)", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(pR0.X, pR0.Y, pR0.Z + 15)
        });
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = $"({WorkPlateData.ROWS - 1},{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(pRC.X, pRC.Y, pRC.Z + 15)
        });

    }

    /// <summary>
    /// 3D 작업판 홀 색상 갱신 (WorkPlateData 상태 반영)
    /// </summary>
    private void Update3DPlate()
    {
        if (_plate3DVisual == null) return;

        for (int r = 0; r < WorkPlateData.ROWS; r++)
        {
            for (int c = 0; c < WorkPlateData.COLS; c++)
            {
                var hole = _plateData.GetHole(c, r);
                var mat = hole.Status switch
                {
                    HoleStatus.Ok => Mat3DOk,
                    HoleStatus.Ng => Mat3DNg,
                    _ => Mat3DEmpty
                };
                var model = _hole3D[r * WorkPlateData.COLS + c];
                if (model.Material != mat)
                {
                    model.Material = mat;
                    model.BackMaterial = mat;
                }
            }
        }
    }

