        if (_bridgeServer == null) { AddLog("브릿지 서버를 먼저 시작하세요."); return; }
        var result = await _bridgeServer.ExecuteAsync("shank 20");
        AddLog($"샹크 20mm: {result}");
    }

    #endregion

    #region 창 닫기

    private void Window_Closing(object sender, System.ComponentModel.CancelEventArgs e)
    {
        _bridgeServer?.StopScenario();
        _bridgeServer?.Stop();
        _robotClient.Dispose();
    }

    #endregion
}

