using System.IO;
using System.Linq;
using System.Text.Json;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Media;
using System.Windows.Media.Media3D;
using HelixToolkit.Wpf;
using TmRobotEx.Bridge;
using TmRobotEx.Robot;
using TmRobotEx.Scenario;
using TmRobotEx.Settings;
using TmRobotEx.WorkPlate;

namespace TmRobotEx;

public partial class MainWindow : Window
{
    private readonly RobotModel _robotModel;
    private readonly TmRobotClient _robotClient;
    private BridgeServer? _bridgeServer;
    private readonly WorkPlateData _plateData;
    private readonly WorkPlatePanel _platePanel;
    private readonly AppSettings _settings;

    // 시나리오 편집
    private ScrewScenario _currentScenario = new() { Name = "새 시나리오" };

    // 갱신 주기 측정
    private DateTime _lastUpdateTime = DateTime.MinValue;
    private int _updateCount;

    // 최신 TCP 좌표 (X,Y,Z,Rx,Ry,Rz)
    private double[] _lastTcp = new double[6];
    private double[] _lastJoints = new double[6];
    // 작업판 3D 오버레이 (3D 모델 좌표 직접 측정, FK 오프셋 불필요)
    //   P1(0,0)→P2(14,0): 15행 방향 (14 간격, ~20mm 피치)
    //   P2(14,0)→P3(14,8): 9열 방향 (8 간격, ~20mm 피치)
    //   볼트: M3
    private static readonly Point3D CalP1 = new(833.5, 510.3, -56.9);   // (0,0)
    private static readonly Point3D CalP2 = new(625.8, 323.3, -62.0);   // (14,0)
    private static readonly Point3D CalP3 = new(731.3, 203.6, -63.4);   // (14,8)

    private readonly GeometryModel3D[] _hole3D = new GeometryModel3D[WorkPlateData.COLS * WorkPlateData.ROWS];
    private ModelVisual3D? _plate3DVisual;
    private LinesVisual3D? _plateBorder;

    private static readonly DiffuseMaterial Mat3DEmpty = new(new SolidColorBrush(Color.FromArgb(180, 120, 120, 120)));
    private static readonly DiffuseMaterial Mat3DOk = new(new SolidColorBrush(Color.FromArgb(230, 80, 200, 80)));
    private static readonly DiffuseMaterial Mat3DNg = new(new SolidColorBrush(Color.FromArgb(230, 220, 60, 60)));
    private static readonly DiffuseMaterial Mat3DCurrent = new(new SolidColorBrush(Color.FromArgb(255, 255, 220, 0)));

    // 캐시된 UI 브러시 (Freeze → 스레드 안전)
    private static readonly SolidColorBrush BrGreen = Frozen(Color.FromRgb(0x60, 0xC0, 0x60));
    private static readonly SolidColorBrush BrGray = Frozen(Color.FromRgb(0x66, 0x66, 0x66));
    private static readonly SolidColorBrush BrRed = Frozen(Color.FromRgb(0xE0, 0x40, 0x40));
    private static readonly SolidColorBrush BrTxtGreen = Frozen(Color.FromRgb(0x90, 0xC0, 0x90));
    private static readonly SolidColorBrush BrTxtGray = Frozen(Color.FromRgb(0x90, 0x90, 0x90));
    private static readonly SolidColorBrush BrYellow = Frozen(Color.FromRgb(0xE0, 0xC0, 0x40));
    private static readonly SolidColorBrush BrCyan = Frozen(Color.FromRgb(0x60, 0xC0, 0xE0));
    private static readonly SolidColorBrush BrIndRed = Frozen(Color.FromRgb(0xC0, 0x60, 0x60));
    private static readonly SolidColorBrush BrTxtRed = Frozen(Color.FromRgb(0xC0, 0x90, 0x90));
    private static SolidColorBrush Frozen(Color c) { var b = new SolidColorBrush(c); b.Freeze(); return b; }

    // 로그 파일
    private static readonly string LogFilePath = Path.Combine(
        AppDomain.CurrentDomain.BaseDirectory, "app.log");
    private int _logWriteCount;

    public MainWindow()
    {
        InitializeComponent();

        // 설정 로드
        _settings = AppSettings.Load();

        // 로봇 3D 모델
        _robotModel = new RobotModel();
        Viewport3D.Children.Add(_robotModel.RootVisual);

        // 로봇 TCP 클라이언트
        _robotClient = new TmRobotClient
        {
            Host = _settings.RobotHost,
            Port = _settings.RobotPort
        };
        _robotClient.DataReceived += OnRobotDataReceived;
        _robotClient.ConnectionChanged += OnRobotConnectionChanged;
        _robotClient.LogMessage += msg => Dispatcher.Invoke(() => AddLog($"[로봇] {msg}"));

        // 작업판
        _plateData = new WorkPlateData();
        _platePanel = new WorkPlatePanel(_plateData, WorkPlateCanvas);
        _platePanel.HoleClicked += OnHoleClicked;

        AddLog("TmRobot Ex 시작");

        Loaded += async (_, _) =>
        {
            SetDefaultCamera();
            _platePanel.Render();
            UpdatePlateStats();
            Update3DPlate();
            Build3DWorkPlate();
            RefreshScenarioComboBox();

            // 자동 연결: 로봇 + 브릿지
            await AutoStartAsync();
        };
    }

    #region 자동 시작

    private async Task AutoStartAsync()
    {
        // 브릿지 서버 자동 시작
        MenuBridgeStart_Click(this, new RoutedEventArgs());
        await Task.Delay(500);

        // 로봇 자동 연결
        MenuRobotConnect_Click(this, new RoutedEventArgs());
    }

    #endregion

    #region 카메라

    private void SetDefaultCamera()
    {
        var cam = Viewport3D.Camera as PerspectiveCamera;
        if (cam == null) return;

        var target = new Point3D(349.2, 424.3, 62.9);
        var cameraPos = new Point3D(1756.9, 108.0, 640.5);

        cam.Position = cameraPos;
        cam.LookDirection = target - cameraPos;
        cam.UpDirection = new Vector3D(-0.068, 0.015, 0.998);
        cam.FieldOfView = 45;

        Viewport3D.CameraController!.CameraTarget = target;
    }

    #endregion

    #region 로봇 연결

    private async void MenuRobotConnect_Click(object sender, RoutedEventArgs e)
    {
        _robotClient.Host = _settings.RobotHost;
        _robotClient.Port = _settings.RobotPort;
        await _robotClient.ConnectAsync();
    }

    private void MenuRobotDisconnect_Click(object sender, RoutedEventArgs e)
    {
        _robotClient.Disconnect();
    }

    private void OnRobotDataReceived(double[] joints, double[] tcp)
    {
        Dispatcher.Invoke(() =>
        {
            _robotModel.SetAllJointAngles(joints);
            Array.Copy(tcp, _lastTcp, Math.Min(tcp.Length, 6));
            Array.Copy(joints, _lastJoints, Math.Min(joints.Length, 6));

            // 갱신 주기
            _updateCount++;
            var now = DateTime.Now;
            var elapsed = (now - _lastUpdateTime).TotalSeconds;
            if (elapsed >= 1.0)
            {
                TxtUpdateRate.Text = $"갱신: {_updateCount / elapsed:F1} Hz";
                _updateCount = 0;
                _lastUpdateTime = now;
            }
        });
    }

    private void OnRobotConnectionChanged(bool connected, string message)
    {
        Dispatcher.Invoke(() =>
        {
            if (connected)
            {
                IndRobot.Fill = BrGreen;
                TxtStatusRobot.Text = $"로봇: {message}";
                TxtStatusRobot.Foreground = BrTxtGreen;
                _lastUpdateTime = DateTime.Now;
                _updateCount = 0;
            }
            else
            {
                IndRobot.Fill = BrGray;
                TxtStatusRobot.Text = "로봇: 미연결";
                TxtStatusRobot.Foreground = BrTxtGray;
                TxtUpdateRate.Text = "갱신: -";
            }
        });
    }

    #endregion

    #region 브릿지 서버

    private async void MenuBridgeStart_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer != null) return;

        try
        {
            _bridgeServer = new BridgeServer(_settings.BridgePort, _settings.ComputeBoxUrl, _settings.ComputeBoxTimeout);
            _bridgeServer.LogMessage += msg =>
            {
                System.Diagnostics.Debug.WriteLine($"[Bridge] {msg}");
                Dispatcher.BeginInvoke(() => AddLog(msg));
            };

            // 확장 명령 연동: 작업판 데이터 제공
            _bridgeServer.PlateData = _plateData;

            // 시나리오 연동 이벤트
            _bridgeServer.StepStarted += OnBridgeStepStarted;
            _bridgeServer.StepCompleted += OnBridgeStepCompleted;
            _bridgeServer.ScenarioCompleted += OnBridgeScenarioCompleted;

            await _bridgeServer.StartAsync();

            IndBridge.Fill = BrGreen;
            TxtStatusBridge.Text = $"브릿지: 포트 {_settings.BridgePort}";
            TxtStatusBridge.Foreground = BrTxtGreen;
            // 브릿지 시작 로그는 BridgeServer.StartAsync()에서 출력

            // CB 연결 확인
            _ = CheckComputeBoxAsync();
        }
        catch (Exception ex)
        {
            AddLog($"브릿지 시작 실패: {ex.Message}");
            _bridgeServer = null;
        }
    }

    private void MenuBridgeStop_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer == null) return;

        _bridgeServer.Stop();
        _bridgeServer = null;

        IndBridge.Fill = BrGray;
        TxtStatusBridge.Text = "브릿지: 중지";
        TxtStatusBridge.Foreground = BrTxtGray;
        IndCb.Fill = BrGray;
        TxtStatusCb.Text = "CB: 미연결";
        TxtStatusCb.Foreground = BrTxtGray;
        AddLog("브릿지 서버 중지");
    }

    private async Task CheckComputeBoxAsync()
    {
        if (_bridgeServer == null) return;
        try
        {
            await _bridgeServer.CbClient.GetBusyAsync();
            Dispatcher.Invoke(() =>
            {
                IndCb.Fill = BrGreen;
                TxtStatusCb.Text = "CB: 연결됨";
                TxtStatusCb.Foreground = BrTxtGreen;
            });
        }
        catch
        {
            Dispatcher.Invoke(() =>
            {
                IndCb.Fill = BrIndRed;
                TxtStatusCb.Text = "CB: 연결 실패";
                TxtStatusCb.Foreground = BrTxtRed;
            });
        }
    }

    #endregion

    #region 작업판

    private void OnHoleClicked(int col, int row)
    {
        // 시나리오 편집 모드일 때 클릭한 홀을 작업 목록에 추가
        if (_bridgeServer?.IsScenarioRunning == true) return;

        var op = new ScrewOperation
        {
            Col = col,
            Row = row,
            Command = "tighten",
            Force = _settings.DefaultForce,
            Length = _settings.DefaultLength,
            Torque = _settings.DefaultTorque
        };
        _currentScenario.Operations.Add(op);
        RefreshScenarioList();
        _platePanel.HighlightHole(col, row);
        AddLog($"홀({col},{row}) 시나리오에 추가");
    }

    private void UpdatePlateStats()
    {
        TxtPlateTotal.Text = _plateData.TotalCount.ToString();
        TxtPlateOk.Text = _plateData.OkCount.ToString();
        TxtPlateNg.Text = _plateData.NgCount.ToString();
        var done = _plateData.OkCount + _plateData.NgCount;
        var percent = _plateData.TotalCount > 0 ? done * 100.0 / _plateData.TotalCount : 0;
        TxtPlatePercent.Text = $"{percent:F0}%";
    }

    #endregion

    #region 시나리오 UI

    private void RefreshScenarioList()
    {
        LstScenario.Items.Clear();
        for (int i = 0; i < _currentScenario.Operations.Count; i++)
        {
            var op = _currentScenario.Operations[i];
            LstScenario.Items.Add($"{i + 1:D3}  ({op.Col},{op.Row})  {op.Command}  F={op.Force}N  L={op.Length}mm  T={op.Torque}Nm");
        }

        // 작업판에 시나리오 순번 표시
        var steps = _currentScenario.Operations
            .Select(op => (op.Col, op.Row))
            .ToList();
        _platePanel.SetScenarioSteps(steps);
    }

    private void LstScenario_SelectionChanged(object sender, SelectionChangedEventArgs e)
    {
        // 선택된 작업의 홀 강조
        if (LstScenario.SelectedIndex >= 0 && LstScenario.SelectedIndex < _currentScenario.Operations.Count)
        {
            var op = _currentScenario.Operations[LstScenario.SelectedIndex];
            _platePanel.HighlightHole(op.Col, op.Row);
        }
    }

    private void BtnScenarioRun_Click(object sender, RoutedEventArgs e)
    {
        if (_currentScenario.Operations.Count == 0)
        {
            AddLog("실행할 시나리오가 비어있습니다.");
            return;
        }
        if (_bridgeServer == null)
        {
            AddLog("브릿지 서버를 먼저 시작하세요.");
            return;
        }

        // 브릿지에 시나리오 연동 (TMflow 대기 모드)
        _bridgeServer.StartScenario(_currentScenario);

        BtnScenarioRun.IsEnabled = false;
        BtnScenarioStop.IsEnabled = true;
        BtnScenarioRemove.IsEnabled = false;

        TxtScenarioStatus.Text = "TMflow 대기 중...";
        TxtScenarioStatus.Foreground = BrYellow;
        AddLog($"시나리오 실행 대기: {_currentScenario.Operations.Count}개 스텝 — TMflow에서 next_step 요청 대기");
    }

    private void BtnScenarioStop_Click(object sender, RoutedEventArgs e)
    {
        _bridgeServer?.StopScenario();
        TxtScenarioStatus.Text = "중지됨";
        TxtScenarioStatus.Foreground = BrIndRed;
        BtnScenarioRun.IsEnabled = true;
        BtnScenarioStop.IsEnabled = false;
        BtnScenarioRemove.IsEnabled = true;
        _platePanel.ClearHighlight();
    }

    private void BtnScenarioRemove_Click(object sender, RoutedEventArgs e)
    {
        if (_currentScenario.Operations.Count == 0) return;
        _currentScenario.Operations.Clear();
        _plateData.Reset();
        _platePanel.Render();
        UpdatePlateStats();
        RefreshScenarioList();
        LvTorque.Items.Clear();
    }

    private void BtnScenarioUp_Click(object sender, RoutedEventArgs e)
    {
        int idx = LstScenario.SelectedIndex;
        if (idx <= 0) return;
        (_currentScenario.Operations[idx], _currentScenario.Operations[idx - 1]) =
            (_currentScenario.Operations[idx - 1], _currentScenario.Operations[idx]);
        RefreshScenarioList();
        LstScenario.SelectedIndex = idx - 1;
    }

    private void BtnScenarioDown_Click(object sender, RoutedEventArgs e)
    {
        int idx = LstScenario.SelectedIndex;
        if (idx < 0 || idx >= _currentScenario.Operations.Count - 1) return;
        (_currentScenario.Operations[idx], _currentScenario.Operations[idx + 1]) =
            (_currentScenario.Operations[idx + 1], _currentScenario.Operations[idx]);
        RefreshScenarioList();
        LstScenario.SelectedIndex = idx + 1;
    }

    #endregion

    #region 브릿지 시나리오 이벤트 (TMflow 연동)

    private void OnBridgeStepStarted(int stepIndex, ScrewOperation op)
    {
        Dispatcher.Invoke(() =>
        {
            TxtScenarioStatus.Text = $"실행 중: {stepIndex + 1}/{_currentScenario.Operations.Count} — 홀({op.Col},{op.Row}) {op.Command}";
            TxtScenarioStatus.Foreground = BrCyan;
            LstScenario.SelectedIndex = stepIndex;
            _platePanel.HighlightHole(op.Col, op.Row);
        });
    }

    private void OnBridgeStepCompleted(int stepIndex, ScrewOperation op, bool success, double torque)
    {
        Dispatcher.Invoke(() =>
        {
            var status = success ? HoleStatus.Ok : HoleStatus.Ng;
            _plateData.SetResult(op.Col, op.Row, status, torque);
            _platePanel.Render();
            UpdatePlateStats();
            Update3DPlate();
            AddLog($"[{stepIndex + 1}] 홀({op.Col},{op.Row}) {(success ? "OK" : "NG")} torque={torque:F2}");

            // 토크 모니터 그리드에 누적 (0.15 미만 빨간색)
            var color = torque >= 0.15
                ? BrGreen
                : BrRed;
            LvTorque.Items.Add(new
            {
                No = stepIndex + 1,
                Hole = $"({op.Col},{op.Row})",
                Torque = torque.ToString("F2"),
                TorqueColor = color
            });
            while (LvTorque.Items.Count > 500)
                LvTorque.Items.RemoveAt(0);
            LvTorque.ScrollIntoView(LvTorque.Items[^1]);
        });
    }

    private void OnBridgeScenarioCompleted()
    {
        Dispatcher.Invoke(() =>
        {
            TxtScenarioStatus.Text = "완료";
            TxtScenarioStatus.Foreground = BrGreen;
            BtnScenarioRun.IsEnabled = true;
            BtnScenarioStop.IsEnabled = false;
            BtnScenarioRemove.IsEnabled = true;
            _platePanel.ClearHighlight();
            AddLog("시나리오 전체 완료");
        });
    }

    #endregion

    #region 시나리오 파일

    private static readonly string ScenariosFile = Path.Combine(
        AppDomain.CurrentDomain.BaseDirectory, "scenarios.json");

    private List<ScrewScenario> _savedScenarios = [];

    private void MenuScenarioNew_Click(object sender, RoutedEventArgs e)
    {
        _currentScenario = new ScrewScenario { Name = "새 시나리오" };
        _plateData.Reset();
        _platePanel.Render();
        UpdatePlateStats();
        RefreshScenarioList();
        AddLog("새 시나리오 생성");
    }

    private void MenuScenarioLoad_Click(object sender, RoutedEventArgs e)
    {
        RefreshScenarioComboBox();
    }

    private void MenuScenarioSave_Click(object sender, RoutedEventArgs e)
    {
        BtnScenarioSave_Click(sender, e);
    }

    /// <summary>
    /// 저장: 현재 시나리오를 scenarios.json에 추가
    /// </summary>
    private void BtnScenarioSave_Click(object sender, RoutedEventArgs e)
    {
        if (_currentScenario.Operations.Count == 0)
        {
            AddLog("저장할 시나리오가 없습니다.");
            return;
        }

        // 타임스탬프 이름
        var name = $"scenario_{DateTime.Now:yyyyMMdd_HHmmss}";
        _currentScenario.Name = name;

        LoadScenariosFile();
        _savedScenarios.Add(new ScrewScenario
        {
            Name = _currentScenario.Name,
            Operations = new List<ScrewOperation>(_currentScenario.Operations)
        });
        SaveScenariosFile();

        RefreshScenarioComboBox();
        AddLog($"시나리오 저장: {name} ({_currentScenario.Operations.Count}개 스텝)");
    }

    /// <summary>
    /// 불러오기: 콤보박스에서 선택된 시나리오 로드
    /// </summary>
    private void BtnScenarioLoad_Click(object sender, RoutedEventArgs e)
    {
        if (CmbScenario.SelectedItem is not string scenarioName)
        {
            AddLog("시나리오를 선택하세요.");
            return;
        }

        LoadScenariosFile();
        var found = _savedScenarios.FirstOrDefault(s => s.Name == scenarioName);
        if (found == null)
        {
            AddLog($"시나리오 '{scenarioName}'을 찾을 수 없습니다.");
            return;
        }

        _currentScenario = new ScrewScenario
        {
            Name = found.Name,
            Operations = new List<ScrewOperation>(found.Operations)
        };
        _plateData.Reset();
        _platePanel.Render();
        UpdatePlateStats();
        RefreshScenarioList();
        AddLog($"시나리오 로드: {scenarioName} ({_currentScenario.Operations.Count}개 스텝)");
    }

    /// <summary>
    /// 콤보박스 드롭다운 열 때 갱신
    /// </summary>
    private void CmbScenario_DropDownOpened(object sender, EventArgs e)
    {
        RefreshScenarioComboBox();
    }

    private void RefreshScenarioComboBox()
    {
        LoadScenariosFile();
        var selected = CmbScenario.SelectedItem as string;
        CmbScenario.Items.Clear();

        foreach (var s in _savedScenarios)
            CmbScenario.Items.Add(s.Name);

        if (selected != null && CmbScenario.Items.Contains(selected))
            CmbScenario.SelectedItem = selected;
    }

    private static readonly JsonSerializerOptions _scenJsonOpts = new()
    {
        WriteIndented = true,
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    private void LoadScenariosFile()
    {
        if (!File.Exists(ScenariosFile)) { _savedScenarios = []; return; }
        try
        {
            var json = File.ReadAllText(ScenariosFile);
            _savedScenarios = JsonSerializer.Deserialize<List<ScrewScenario>>(json, _scenJsonOpts) ?? [];
        }
        catch { _savedScenarios = []; }
    }

    private void SaveScenariosFile()
    {
        var json = JsonSerializer.Serialize(_savedScenarios, _scenJsonOpts);
        File.WriteAllText(ScenariosFile, json);
    }

    #endregion

    #region 설정

    private void MenuSettings_Click(object sender, RoutedEventArgs e)
    {
        var dlg = new SettingsDialog(_settings) { Owner = this };
        if (dlg.ShowDialog() == true)
        {
            _settings.Save();
            _robotClient.Host = _settings.RobotHost;
            _robotClient.Port = _settings.RobotPort;
            AddLog("설정 저장 완료");
        }
    }

    #endregion

    #region 로그

    private void AddLog(string message)
    {
        var entry = $"[{DateTime.Now:HH:mm:ss.fff}] {message}";
        LstLog.Items.Add(entry);
        while (LstLog.Items.Count > 500)
            LstLog.Items.RemoveAt(0);
        LstLog.ScrollIntoView(LstLog.Items[^1]);

        try
        {
            // 1000줄마다 파일 크기 체크 (10MB 초과 시 로테이션)
            if (++_logWriteCount % 1000 == 0 && File.Exists(LogFilePath))
            {
                var fi = new FileInfo(LogFilePath);
                if (fi.Length > 10 * 1024 * 1024)
                {
                    var bak = LogFilePath + ".bak";
                    if (File.Exists(bak)) File.Delete(bak);
                    File.Move(LogFilePath, bak);
                }
            }
            File.AppendAllText(LogFilePath, entry + Environment.NewLine);
        }
        catch { }
    }

    private void BtnLogCamera_Click(object sender, RoutedEventArgs e)
    {
        var cam = Viewport3D.Camera as PerspectiveCamera;
        if (cam == null) { AddLog("카메라 없음"); return; }

        var p = cam.Position;
        var d = cam.LookDirection;
        var u = cam.UpDirection;
        var target = Viewport3D.CameraController?.CameraTarget ?? new Point3D();

        AddLog("━━━ 카메라 위치 ━━━");
        AddLog($"  Position = new Point3D({p.X:F1}, {p.Y:F1}, {p.Z:F1})");
        AddLog($"  LookDirection = target - cameraPos");
        AddLog($"  UpDirection = new Vector3D({u.X:F3}, {u.Y:F3}, {u.Z:F3})");
        AddLog($"  FieldOfView = {cam.FieldOfView:F1}");
        AddLog($"  CameraTarget = new Point3D({target.X:F1}, {target.Y:F1}, {target.Z:F1})");
        AddLog("━━━━━━━━━━━━━━━━━");
    }

    #endregion

    #region 작업판 3D 오버레이

    /// <summary>
    /// 3D 작업판 재생성
    /// </summary>
    private void Rebuild3DWorkPlate()
    {
        if (_plate3DVisual != null)
            Viewport3D.Children.Remove(_plate3DVisual);
        if (_plateBorder != null)
            Viewport3D.Children.Remove(_plateBorder);

        var toRemove = Viewport3D.Children
            .OfType<BillboardTextVisual3D>()
            .Where(b => b.Text.StartsWith("("))
            .ToList();
        foreach (var b in toRemove)
            Viewport3D.Children.Remove(b);

        Build3DWorkPlate();
    }

    /// <summary>
    /// 단위 구체 메시 생성 (반지름 1, 원점 중심)
    /// </summary>
    private static MeshGeometry3D CreateUnitSphereMesh(int thetaDiv = 8, int phiDiv = 5)
    {
        var mesh = new MeshGeometry3D();
        for (int pi = 0; pi <= phiDiv; pi++)
        {
            double phi = Math.PI * pi / phiDiv;
            for (int ti = 0; ti <= thetaDiv; ti++)
            {
                double theta = 2 * Math.PI * ti / thetaDiv;
                double x = Math.Sin(phi) * Math.Cos(theta);
                double y = Math.Sin(phi) * Math.Sin(theta);
                double z = Math.Cos(phi);
                mesh.Positions.Add(new Point3D(x, y, z));
                mesh.Normals.Add(new Vector3D(x, y, z));
            }
        }
        for (int pi = 0; pi < phiDiv; pi++)
        {
            for (int ti = 0; ti < thetaDiv; ti++)
            {
                int i0 = pi * (thetaDiv + 1) + ti;
                int i1 = i0 + 1;
                int i2 = i0 + thetaDiv + 1;
                int i3 = i2 + 1;
                mesh.TriangleIndices.Add(i0);
                mesh.TriangleIndices.Add(i2);
                mesh.TriangleIndices.Add(i1);
                mesh.TriangleIndices.Add(i1);
                mesh.TriangleIndices.Add(i2);
                mesh.TriangleIndices.Add(i3);
            }
        }
        mesh.Freeze();
        return mesh;
    }

    private void Build3DWorkPlate()
    {
        // 3D 모델 좌표 직접 사용 (FK 오프셋 불필요)
        var p1 = CalP1;
        var p2 = CalP2;
        var p3 = CalP3;

        // 그리드 벡터
        var rowStep = (p2 - p1) / (WorkPlateData.ROWS - 1);  // 15행, 14 간격
        var colStep = (p3 - p2) / (WorkPlateData.COLS - 1);  // 9열, 8 간격

        // 공유 구체 메시 (반지름 5mm 스케일 적용)
        var sphereMesh = CreateUnitSphereMesh();
        var group = new Model3DGroup();
        var yellowBrush = new SolidColorBrush(Color.FromRgb(255, 204, 0));

        // 135개 홀
        for (int r = 0; r < WorkPlateData.ROWS; r++)
        {
            for (int c = 0; c < WorkPlateData.COLS; c++)
            {
                var pos = p1 + r * rowStep + c * colStep;
                var tg = new Transform3DGroup();
                tg.Children.Add(new ScaleTransform3D(5, 5, 5));
                tg.Children.Add(new TranslateTransform3D(pos.X, pos.Y, pos.Z));

                var model = new GeometryModel3D
                {
                    Geometry = sphereMesh,
                    Material = Mat3DEmpty,
                    BackMaterial = Mat3DEmpty,
                    Transform = tg
                };
                _hole3D[r * WorkPlateData.COLS + c] = model;
                group.Children.Add(model);
            }
        }

        _plate3DVisual = new ModelVisual3D { Content = group };
        Viewport3D.Children.Add(_plate3DVisual);

        // 테두리선 (노란색)
        var p00 = p1;
        var pR0 = p1 + (WorkPlateData.ROWS - 1) * rowStep;
        var p0C = p1 + (WorkPlateData.COLS - 1) * colStep;
        var pRC = p1 + (WorkPlateData.ROWS - 1) * rowStep + (WorkPlateData.COLS - 1) * colStep;

        _plateBorder = new LinesVisual3D
        {
            Color = Colors.Yellow,
            Thickness = 2,
            Points = new Point3DCollection(new[] { p00, pR0, pR0, pRC, pRC, p0C, p0C, p00 })
        };
        Viewport3D.Children.Add(_plateBorder);

        // 코너 라벨
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = "(0,0)", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(p00.X, p00.Y, p00.Z + 15)
        });
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = $"(0,{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(p0C.X, p0C.Y, p0C.Z + 15)
        });
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = $"({WorkPlateData.ROWS - 1},0)", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(pR0.X, pR0.Y, pR0.Z + 15)
        });
        Viewport3D.Children.Add(new BillboardTextVisual3D
        {
            Text = $"({WorkPlateData.ROWS - 1},{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
            Position = new Point3D(pRC.X, pRC.Y, pRC.Z + 15)
        });

    }

    /// <summary>
    /// 3D 작업판 홀 색상 갱신 (WorkPlateData 상태 반영)
    /// </summary>
    private void Update3DPlate()
    {
        if (_plate3DVisual == null) return;

        for (int r = 0; r < WorkPlateData.ROWS; r++)
        {
            for (int c = 0; c < WorkPlateData.COLS; c++)
            {
                var hole = _plateData.GetHole(c, r);
                var mat = hole.Status switch
                {
                    HoleStatus.Ok => Mat3DOk,
                    HoleStatus.Ng => Mat3DNg,
                    _ => Mat3DEmpty
                };
                var model = _hole3D[r * WorkPlateData.COLS + c];
                if (model.Material != mat)
                {
                    model.Material = mat;
                    model.BackMaterial = mat;
                }
            }
        }
    }

    #endregion

    #region 로그 복사/지우기

    private void BtnLogCopy_Click(object sender, RoutedEventArgs e)
    {
        // 선택된 항목이 있으면 선택만, 없으면 전체
        var items = LstLog.SelectedItems.Count > 0 ? LstLog.SelectedItems : LstLog.Items;
        var text = string.Join(Environment.NewLine, items.Cast<object>().Select(o => o.ToString()));
        if (!string.IsNullOrEmpty(text))
        {
            Clipboard.SetText(text);
            AddLog($"클립보드 복사 완료 ({items.Count}줄)");
        }
    }

    private void BtnLogClear_Click(object sender, RoutedEventArgs e)
    {
        LstLog.Items.Clear();
    }

    private void BtnExit_Click(object sender, RoutedEventArgs e)
    {
        Close();
    }

    #endregion

    #region 스크루드라이버 제어

    private async void BtnSdRecover_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer == null) { AddLog("브릿지 서버를 먼저 시작하세요."); return; }
        AddLog("오류 해제 중...");
        var result = await _bridgeServer.ExecuteAsync("recover");
        AddLog($"오류 해제: {result}");
    }

    private async void BtnSdShank55_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer == null) { AddLog("브릿지 서버를 먼저 시작하세요."); return; }
        var result = await _bridgeServer.ExecuteAsync("shank 55");
        AddLog($"샹크 55mm: {result}");
    }

    private async void BtnSdShank20_Click(object sender, RoutedEventArgs e)
    {
        if (_bridgeServer == null) { AddLog("브릿지 서버를 먼저 시작하세요."); return; }
        var result = await _bridgeServer.ExecuteAsync("shank 20");
        AddLog($"샹크 20mm: {result}");
    }

    #endregion

    #region 창 닫기

    private void Window_Closing(object sender, System.ComponentModel.CancelEventArgs e)
    {
        _bridgeServer?.StopScenario();
        _bridgeServer?.Stop();
        _robotClient.Dispose();
    }

    #endregion
}

