    private void BtnScenarioRun_Click(object sender, RoutedEventArgs e)
    {
        if (_currentScenario.Operations.Count == 0)
        {
            AddLog("실행할 시나리오가 비어있습니다.");
            return;
        }
        if (_bridgeServer == null)
        {
            AddLog("브릿지 서버를 먼저 시작하세요.");
            return;
        }

        // 브릿지에 시나리오 연동 (TMflow 대기 모드)
        _bridgeServer.StartScenario(_currentScenario);

        BtnScenarioRun.IsEnabled = false;
        BtnScenarioStop.IsEnabled = true;
        BtnScenarioRemove.IsEnabled = false;

        TxtScenarioStatus.Text = "TMflow 대기 중...";
        TxtScenarioStatus.Foreground = BrYellow;
        AddLog($"시나리오 실행 대기: {_currentScenario.Operations.Count}개 스텝 — TMflow에서 next_step 요청 대기");
