    private void BtnScenarioUp_Click(object sender, RoutedEventArgs e)
    {
        int idx = LstScenario.SelectedIndex;
        if (idx <= 0) return;
        (_currentScenario.Operations[idx], _currentScenario.Operations[idx - 1]) =
            (_currentScenario.Operations[idx - 1], _currentScenario.Operations[idx]);
        RefreshScenarioList();
        LstScenario.SelectedIndex = idx - 1;
    }

    private void BtnScenarioDown_Click(object sender, RoutedEventArgs e)
    {
        int idx = LstScenario.SelectedIndex;
        if (idx < 0 || idx >= _currentScenario.Operations.Count - 1) return;
        (_currentScenario.Operations[idx], _currentScenario.Operations[idx + 1]) =
            (_currentScenario.Operations[idx + 1], _currentScenario.Operations[idx]);
        RefreshScenarioList();
        LstScenario.SelectedIndex = idx + 1;
    }

