    /// <summary>
    /// 저장: 현재 시나리오를 scenarios.json에 추가
    /// </summary>
    private void BtnScenarioSave_Click(object sender, RoutedEventArgs e)
    {
        if (_currentScenario.Operations.Count == 0)
        {
            AddLog("저장할 시나리오가 없습니다.");
            return;
        }

        // 타임스탬프 이름
        var name = $"scenario_{DateTime.Now:yyyyMMdd_HHmmss}";
        _currentScenario.Name = name;

        LoadScenariosFile();
        _savedScenarios.Add(new ScrewScenario
        {
            Name = _currentScenario.Name,
            Operations = new List<ScrewOperation>(_currentScenario.Operations)
        });
        SaveScenariosFile();

        RefreshScenarioComboBox();
        AddLog($"시나리오 저장: {name} ({_currentScenario.Operations.Count}개 스텝)");
    }

    /// <summary>
    /// 불러오기: 콤보박스에서 선택된 시나리오 로드
    /// </summary>
    private void BtnScenarioLoad_Click(object sender, RoutedEventArgs e)
    {
        if (CmbScenario.SelectedItem is not string scenarioName)
        {
            AddLog("시나리오를 선택하세요.");
            return;
        }

        LoadScenariosFile();
        var found = _savedScenarios.FirstOrDefault(s => s.Name == scenarioName);
        if (found == null)
        {
            AddLog($"시나리오 '{scenarioName}'을 찾을 수 없습니다.");
            return;
        }

        _currentScenario = new ScrewScenario
        {
            Name = found.Name,
            Operations = new List<ScrewOperation>(found.Operations)
        };
        _plateData.Reset();
        _platePanel.Render();
        UpdatePlateStats();
        RefreshScenarioList();
        AddLog($"시나리오 로드: {scenarioName} ({_currentScenario.Operations.Count}개 스텝)");
    }

