    private void AddLog(string message)
    {
        var entry = $"[{DateTime.Now:HH:mm:ss.fff}] {message}";
        LstLog.Items.Add(entry);
        while (LstLog.Items.Count > 500)
            LstLog.Items.RemoveAt(0);
        LstLog.ScrollIntoView(LstLog.Items[^1]);

        try
        {
            // 1000줄마다 파일 크기 체크 (10MB 초과 시 로테이션)
            if (++_logWriteCount % 1000 == 0 && File.Exists(LogFilePath))
            {
                var fi = new FileInfo(LogFilePath);
                if (fi.Length > 10 * 1024 * 1024)
                {
                    var bak = LogFilePath + ".bak";
                    if (File.Exists(bak)) File.Delete(bak);
                    File.Move(LogFilePath, bak);
                }
            }
            File.AppendAllText(LogFilePath, entry + Environment.NewLine);
        }
        catch { }
    }

